export const CURRICULUM = {
  L0:{icon:'🌍',tag:'Level 0',name:'Why Should I Care?',desc:'Motivation, threat landscape, and your roadmap — zero math',color:'sky',topics:[
    {id:'t01',title:'The 30-second version',
      learn:`Quantum computers will one day break the encryption that protects <b>everything</b> — your bank, your messages, government secrets, medical records, and national infrastructure. The race is on to build new <b>quantum-safe</b> cryptography before that day arrives. That field — spanning math, physics, engineering, and policy — is <b>quantum security</b>. It's one of the most important and fastest-growing areas in technology, with real jobs today in migration, standards, and research.`,
      deep:`Three pillars: <b>(1) Post-quantum cryptography (PQC)</b> — new algorithms (Kyber, Dilithium). <b>(2) Quantum communications</b> — QKD, quantum networks. <b>(3) Quantum-enabled threats</b> — Shor, Grover, cryptanalysis. This academy covers all three so you can choose your path.`,
      analogy:`Imagine every lock in the world used the same key design — and someone invented a machine that copies that key in minutes. You'd need to replace every lock fast. That's exactly where we are with encryption.`,
      res:[['↗ NIST: why PQC matters','https://www.nist.gov/cybersecurity/post-quantum-cryptography']],
      extraResources:[['↗ NIST PQC project','https://csrc.nist.gov/projects/post-quantum-cryptography']],
      steps:['Read the short intro above twice.','Ask yourself: what on your phone is protected by encryption? (Answer: basically everything — messages, banking, passwords.)','Write one sentence: why does breaking encryption matter to ordinary people?'],
      game:null,
      quiz:{q:'What is the core problem quantum security solves?',opts:['Making computers faster','Quantum computers will break current encryption','Building better phones','Mining cryptocurrency'],correct:1,ok:'Exactly. Quantum computers threaten the encryption protecting everything — quantum security is about defending against that.',no:'The core issue: future quantum computers can break today\'s encryption. Quantum security is the defense.'}},
    {id:'t02',title:'Harvest now, decrypt later',
      learn:`Here's the scary part: attackers are <b>already</b> stealing encrypted data today, storing it, and waiting. When quantum computers mature, they'll decrypt it all retroactively. So data you send today that needs to stay secret for 10+ years is <b>already at risk</b>. This is why the migration is urgent — not a "someday" problem.`,
      deep:`HNDL targets ciphertext with long confidentiality requirements: government archives, medical records, intellectual property, recorded VPN traffic, and backups. The adversary does not need to break crypto today — storage is cheap.\n\nThis shifts risk management: “when will quantum break RSA?” matters less than “how long must this data stay secret?” If the answer is 15 years, you must assume an adversary may decrypt it later unless you migrate to PQC or re-encrypt.\n\nOperational response: classify data by lifetime, prioritize asymmetric algorithms for replacement, and avoid transmitting long-term secrets under RSA/ECC where possible.`,
      keyPoints:['Attack stores ciphertext now, decrypts later','Long confidentiality windows are already at risk','Migration urgency is driven by data lifetime','Not only nation-states — ransomware groups hoard data too'],
      flashcards:[{q:'What is HNDL?',a:'Harvest now, decrypt later — store ciphertext today, decrypt when quantum computers exist.'}],
      analogy:`Like someone photographing your locked diary now, knowing they'll get the key in a few years. The lock being strong today doesn't help if the secret matters tomorrow.`,
      res:[],
      steps:['Think of data that must stay secret for 10+ years (medical records, state secrets, IP).','Understand: that data is vulnerable NOW even though quantum computers aren\'t ready.','This is the #1 reason organizations are migrating early.'],
      game:null,
      quiz:{q:'Why is "harvest now, decrypt later" urgent today?',opts:['Quantum computers already exist at scale','Encrypted data stolen now can be decrypted later when quantum matures','It makes encryption slower','It only affects old computers'],correct:1,ok:'Right — long-lived secrets sent today can be harvested and decrypted years later. The clock is already ticking.',no:'The threat: data stolen and stored today gets decrypted once quantum computers mature. Long-term secrets are already exposed.'}},
    {id:'t03',title:'Map of the whole journey',
      learn:`You'll go: <b>math foundations</b> → <b>code</b> → <b>quantum mechanics</b> → <b>quantum algorithms</b> → <b>classical crypto</b> → <b>the threat</b> → <b>the defenses</b> → <b>specialize</b>. Don't worry about understanding it all now. Each level unlocks the next. By the end you'll understand all 6 branches of quantum security and can pick one to go deep.`,
      analogy:`Like learning to cook: first knife skills and ingredients (math), then basic recipes (quantum basics), then your own dishes (algorithms), then opening a restaurant in your chosen cuisine (specialization).`,
      res:[],
      steps:['Skim the level names below to see the journey.','Accept that early levels feel basic — they\'re the foundation everything rests on.','Commit to one topic at a time. That\'s all it takes.'],
      game:null,
      quiz:{q:'What\'s the right mindset for this journey?',opts:['Memorize everything immediately','One topic at a time, foundations first','Skip to the advanced stuff','Only do the games'],correct:1,ok:'Yes — foundations first, one topic at a time. Each builds on the last.',no:'Foundations first, one step at a time. Rushing past the basics makes the advanced material impossible.'}}
  ]},

  L1:{icon:'📐',tag:'Level 1',name:'Math Foundation',desc:'Vectors, matrices, complex numbers, probability, bra-ket',color:'cyan',topics:[
    {id:'t11',title:'Vectors',
      learn:`A <b>vector</b> is a list of numbers describing a point or direction. [3,2] = "3 right, 2 up." A qubit's state is a vector of 2 complex numbers. Everything quantum is built on vectors.`,
      deep:`In linear algebra, a vector is best thought of as an element of a <b>vector space</b>. For quantum, the relevant space is usually \u2102\u207F: vectors whose components are complex numbers. A single qubit lives in \u2102\u00b2, so we represent its state as a 2-component complex vector \u03c8 = [\u03b1, \u03b2]. The requirement \u201cprobabilities add to 1\u201d becomes a normalization constraint: |\u03b1|<sup>2</sup> + |\u03b2|<sup>2</sup> = 1.\n\nTwo quantum states can be added, and they can be scaled. That\u2019s not just bookkeeping: superposition is literally linear combination. If \u03c8\u2081 and \u03c8\u2082 are valid states, then c\u2081\u03c8\u2081 + c\u2082\u03c8\u2082 is a state after normalization. This linearity is why interference exists: amplitudes add, then probabilities come from squared magnitudes.\n\nYou\u2019ll also meet <b>inner products</b> (dot products). In complex vector spaces the inner product uses a conjugate: \u27e8x, y\u27e9 = \u03a3 conj(x\u1d62) y\u1d62. Inner products give lengths (norms) and angles, and they drive measurement probabilities.\n\nFinally: the basis vectors |0\u27e9=[1,0] and |1\u27e9=[0,1] are just a convenient coordinate system. Quantum computing is mostly about choosing a basis, transforming vectors, and interpreting the results after measurement.`,
      keyPoints:['A qubit state is a complex vector in \u2102\u00b2','Normalization: |\u03b1|^2 + |\u03b2|^2 = 1','Superposition is linear combination of vectors','Inner product uses complex conjugate','Basis vectors |0\u27e9, |1\u27e9 are coordinates, not magic'],
      analogy:`A home address: "123 Main, Floor 4" — numbers pinpointing one spot. A vector does that in math space.`,
      res:[['▶ 3Blue1Brown Vectors','https://www.youtube.com/watch?v=fNk_zzaMoSs'],['↗ Khan practice','https://www.khanacademy.org/math/linear-algebra/vectors-and-spaces']],
      steps:['Watch the 9-min vectors video.','Plot [2,3], [-1,4], [0,-2] on paper as arrows.','Add [2,3]+[1,1] head-to-tail.','Use the Vector Plotter game →'],
      exercise:{
        prompt:`Add two 2D vectors. Input: <code>ax ay bx by</code> → output: <code>cx cy</code> where c = a + b component-wise.`,
        starter:`function solve(input) {\n  const [ax,ay,bx,by] = input.trim().split(/\\s+/).map(Number);\n  return '';\n}\n`,
        tests:[
          { input: '1 0 0 1', expected: '1 1' },
          { input: '2 3 1 1', expected: '3 4' },
          { input: '-1 2 3 -2', expected: '2 0' }
        ],
        solution:`function solve(input){const [ax,ay,bx,by]=input.trim().split(/\\s+/).map(Number);return \`\${ax+bx} \${ay+by}\`;}`
      },
      flashcards:[{q:'How do you add vectors?',a:'Component-wise: [a,b]+[c,d]=[a+c,b+d].'},{q:'Why normalize qubit states?',a:'So probabilities sum to 1 (|α|²+|β|²=1).'}],
      game:'vector',
      quiz:{q:'A=[1,0], B=[0,1]. A+B = ?',opts:['[0,0]','[1,1]','[1,0]','[2,1]'],correct:1,ok:'Component-wise: [1,1]. How quantum states combine.',no:'Add each slot: 1+0=1, 0+1=1 → [1,1].'}},
    {id:'t12',title:'Matrices',
      learn:`A <b>matrix</b> transforms a vector — rotates, flips, scales it. Every quantum gate IS a matrix. [[0,1],[1,0]] swaps values = the quantum NOT gate.`,
      deep:`A matrix represents a <b>linear map</b>. The important property is linearity: M(a\u22c5x + b\u22c5y) = a\u22c5Mx + b\u22c5My. Quantum evolution (ignoring measurement) is linear, so gates must be linear maps.\n\nIn quantum computing, valid single-qubit gates are 2\u00d72 matrices that are <b>unitary</b>. Unitary means U\u2020U = I (where U\u2020 is conjugate transpose). Unitary matrices preserve inner products and therefore preserve total probability (normalization). This is the mathematical reason gates don\u2019t \u201ccreate\u201d or \u201cdestroy\u201d probability.\n\nCommon examples: X = [[0,1],[1,0]] swaps amplitudes; Z = [[1,0],[0,-1]] flips the phase of |1\u27e9; H = (1/\u221a2)[[1,1],[1,-1]] creates superposition. The global phase of a state (multiplying by e<sup>i\u03b8</sup>) doesn\u2019t change measurement probabilities, but <b>relative phase</b> matters because it changes interference when amplitudes recombine.\n\nWhen you move to multi-qubit systems, gates become larger matrices (4\u00d74, 8\u00d78, \u2026) acting on tensor-product state vectors. The same unitarity rule applies \u2014 it\u2019s just bigger linear algebra.`,
      keyPoints:['Gates are linear maps represented by matrices','Quantum gates are unitary: U\u2020U=I','Unitary preserves normalization (total probability)','Relative phase matters for interference','Multi-qubit gates are larger unitaries on tensor products'],
      analogy:`A function machine: vector in, transformed vector out. Gates are machines that twist qubits usefully.`,
      res:[['▶ 3B1B Transformations','https://www.youtube.com/watch?v=kYB8IZa5AuE'],['↗ Khan matrices','https://www.khanacademy.org/math/linear-algebra/matrix-transformations']],
      steps:['Watch the transformations video.','Compute [[2,0],[0,3]]×[1,1].','Compute [[0,1],[1,0]]×[3,5] — the X gate!','Play with the Gate Lab →'],
      exercise:{
        prompt:`Apply 2×2 matrix M to vector v. Input: six numbers <code>m00 m01 m10 m11 vx vy</code> (row-major M, then v).`,
        formatExample:'Return two numbers as a space-separated string, e.g. "0 1"',
        hints:['Row 0: m00*vx + m01*vy. Row 1: m10*vx + m11*vy.','X gate [[0,1],[1,0]] on [1,0] gives [0,1].'],
        starter:`function solve(input) {\n  const p = input.trim().split(/\\s+/).map(Number);\n  return '';\n}\n`,
        tests:[
          { input: '0 1 1 0 1 0', expected: '0 1' },
          { input: '1 0 0 1 3 5', expected: '3 5' },
          { input: '2 0 0 3 1 1', expected: '2 3' }
        ],
        solution:`function solve(input){const [m00,m01,m10,m11,vx,vy]=input.trim().split(/\\s+/).map(Number);const x=m00*vx+m01*vy;const y=m10*vx+m11*vy;return x+' '+y;}`
      },
      game:'gate',
      quiz:{q:'X gate [[0,1],[1,0]] applied to [1,0]?',opts:['[1,0]','[0,1]','[2,0]','[0,0]'],correct:1,ok:'[0·1+1·0, 1·1+0·0]=[0,1]. Flips |0⟩→|1⟩.',no:'Rows times column: top=0, bottom=1 → [0,1].'}},
    {id:'t13',title:'Complex numbers',
      learn:`A <b>complex number</b> = real + imaginary, like 3+2i where i=√(-1). Qubit amplitudes are complex — this enables <b>interference</b>, the source of quantum power.`,
      deep:`Complex numbers let us represent both magnitude and phase. You can write a complex number as a+bi (Cartesian form) or as r e<sup>i\u03b8</sup> (polar form), where r is magnitude and \u03b8 is phase. The identity e<sup>i\u03b8</sup> = cos\u03b8 + i sin\u03b8 (Euler\u2019s formula) connects them.\n\nWhy does quantum need complex amplitudes? Because interference depends on phase. Two paths with equal magnitude can add constructively (phases align) or destructively (phases oppose). If amplitudes were only real and nonnegative, you couldn\u2019t represent \u201ccancellation\u201d in the same way.\n\nMeasurement probabilities use squared magnitude: |a+bi|<sup>2</sup> = a<sup>2</sup>+b<sup>2</sup>. Note: the sign of a and b and the phase \u03b8 affect how amplitudes combine <i>before</i> you square them.\n\nIn practice, many beginner circuits can be simulated with real amplitudes, but the moment you study phase gates, the quantum Fourier transform, or interference-based algorithms, complex numbers become unavoidable.`,
      keyPoints:['Complex = magnitude + phase','Polar form r e^{i\u03b8} is natural for phases','Probabilities use |amplitude|^2','Phase affects interference when amplitudes add','Many quantum gates change phase rather than probability directly'],
      analogy:`GPS coordinates: two values (lat, long) = one location. 3+2i = one number on a 2D plane.`,
      res:[['↗ Khan complex numbers','https://www.khanacademy.org/math/algebra2/x2ec2f6f830c9fb89:complex']],
      steps:['Do Khan complex numbers intro.','Calculate (2+3i)+(1+4i).','Calculate (2+3i)×(1+2i), remember i²=-1.','Find |3+4i| = √(3²+4²).'],
      game:null,
      quiz:{q:'(1+2i)+(3+4i) = ?',opts:['4+6i²','4+6i','3+8i','4-6i'],correct:1,ok:'Reals: 4. Imaginary: 6i. → 4+6i.',no:'Add reals & imaginaries separately: 4+6i.'}},
    {id:'t14',title:'Probability & the Born rule',
      learn:`Measuring a qubit gives random 0 or 1. Probability = <b>amplitude squared</b>. State [0.6,0.8] → P(0)=0.36, P(1)=0.64, summing to 1. This is the Born rule — the bridge from quantum math to real outcomes.`,
      deep:`The Born rule says: if a state is |\u03c8\u27e9 = \u03a3\u1d62 \u03b1\u1d62 |i\u27e9 in some measurement basis \u007b|i\u27e9\u007d, then outcome i occurs with probability |\u03b1\u1d62|<sup>2</sup>. The basis matters: measuring in the computational basis (\u007b|0\u27e9,|1\u27e9\u007d) vs another basis can change the probabilities even though the underlying state is the same.\n\nNormalization is not optional: |\u03b1|<sup>2</sup>+|\u03b2|<sup>2</sup>=1 for a qubit. Unitary gates preserve this automatically, which is why they\u2019re the allowed operations for closed-system evolution.\n\nA subtle point: amplitudes can be negative or complex. You don\u2019t interpret \u03b1 directly as probability; you interpret |\u03b1|<sup>2</sup>. That is exactly why interference can occur: amplitudes add first, then you square.\n\nFor cryptography, the key takeaway is operational: measurement injects irreducible randomness. This randomness (and disturbance under eavesdropping) is what QKD and QRNG build on.`,
      keyPoints:['Born rule: outcome prob = |amplitude|^2 in the measurement basis','Measurement basis choice changes probabilities','Normalization ensures probabilities sum to 1','Amplitudes add; probabilities come after squaring (interference)','Measurement randomness is a resource for QKD/QRNG'],
      analogy:`A weighted coin: 70% heads. Unpredictable per flip, but the odds are fixed. Measuring forces it to land.`,
      res:[['↗ Khan probability','https://www.khanacademy.org/math/statistics-probability/probability-library']],
      steps:['State [1/√2,1/√2]: square first → P(0)=0.5. P(1)?','Do Khan conditional probability.','If P(0)=0.3, find P(1).','Try the Quantum Coin game →'],
      exercise:{
        prompt:`Born rule: P(0) = α² / (α² + β²) for state [α, β]. Input: <code>alpha beta</code> (real numbers).`,
        formatExample:'Return probability as a decimal string, e.g. "0.36"',
        hints:['Square alpha for the numerator.','Add alpha² + beta² for the denominator.'],
        starter:`function solve(input) {\n  const [a,b] = input.trim().split(/\\s+/).map(Number);\n  return '';\n}\n`,
        tests:[
          { input: '0.6 0.8', expected: '0.36' },
          { input: '1 0', expected: '1' },
          { input: '0.5 0.5', expected: '0.5' }
        ],
        solution:`function solve(input){const [a,b]=input.trim().split(/\\s+/).map(Number);const p=(a*a)/(a*a+b*b);return String(Math.round(p*100)/100);}`
      },
      game:'coin',
      quiz:{q:'Qubit [0.8,0.6]. P(measuring 1)?',opts:['0.6','0.64','0.36','0.5'],correct:2,ok:'0.6²=0.36. Check: 0.64+0.36=1 ✓',no:'Square the amplitude: 0.6²=0.36.'}},
    {id:'t15',title:'Dirac notation (bra-ket)',
      learn:`Physicists write qubit states with <b>bra-ket notation</b>: |0⟩ and |1⟩ are the basis states ("ket zero", "ket one"). A general state is α|0⟩+β|1⟩ where α,β are amplitudes. You'll see this symbol everywhere — it's just shorthand for the vectors you already know. |0⟩=[1,0], |1⟩=[0,1].`,
      deep:`Dirac notation is a compact way to write vectors and inner products. A <b>ket</b> |\u03c8\u27e9 is a column vector. A <b>bra</b> \u27e8\u03c8| is its conjugate transpose. The inner product \u27e8\u03c6|\u03c8\u27e9 is a complex number. The outer product |\u03c6\u27e9\u27e8\u03c8| is a matrix (an operator).\n\nThis notation is more than style: it scales cleanly. Multi-qubit states use tensor products like |00\u27e9 = |0\u27e9\u2297|0\u27e9. Gates become operators acting on these spaces.\n\nYou\u2019ll also see projectors like |0\u27e9\u27e80|, which mean \u201ckeep only the |0\u27e9 component\u201d in a decomposition. Measurements can be written as a set of projectors, which connects nicely to the Born rule.\n\nIf you can translate between |\u03c8\u27e9 and [\u03b1,\u03b2], you\u2019re fluent. The rest is learning to read inner products, outer products, and tensor products without panic.`,
      keyPoints:['Ket = vector |\u03c8\u27e9, bra = conjugate transpose \u27e8\u03c8|','Inner product \u27e8\u03c6|\u03c8\u27e9 is a scalar; outer product |\u03c6\u27e9\u27e8\u03c8| is a matrix','Tensor products build multi-qubit states like |00\u27e9','Projectors like |0\u27e9\u27e80| describe measurement mathematically','Bra-ket is notation that scales to big systems'],
      analogy:`Like writing "½" instead of "one divided by two" — same thing, compact symbol. |0⟩ just means the vector [1,0].`,
      res:[['↗ Quantum Country','https://quantum.country/qcvc']],
      steps:['Memorize: |0⟩=[1,0], |1⟩=[0,1].','Write the superposition (|0⟩+|1⟩)/√2 as a vector. (Answer: [0.707,0.707])','Practice reading α|0⟩+β|1⟩ as [α,β].','Build states in the Bra-Ket game →'],
      game:'braket',
      quiz:{q:'What vector does |1⟩ represent?',opts:['[1,0]','[0,1]','[1,1]','[0,0]'],correct:1,ok:'|1⟩=[0,1]. And |0⟩=[1,0]. Just compact notation for vectors.',no:'|1⟩ is the second basis state = [0,1]. (|0⟩=[1,0].)'}}
    ,{id:'t16',title:'Modular arithmetic (clock math)',
      learn:`<b>Modular arithmetic</b> is "clock math" — numbers wrap around. 14 mod 12 = 2 (2 o'clock). RSA and almost all public-key crypto run on modular arithmetic with huge numbers. The "mod" operation is the beating heart of classical cryptography, so you need to be comfortable with it.`,
      deep:`Modular arithmetic means we work in the set \u007b0,1,\u2026,n-1\u007d with addition and multiplication \u201cwrapping around\u201d by n. Two numbers are congruent mod n if they differ by a multiple of n: a \u2261 b (mod n).\n\nFor crypto, the key idea is that modular multiplication and exponentiation behave well, but reversing them can be hard. Example: modular exponentiation a<sup>x</sup> mod n is easy to compute even for huge x via repeated squaring. Many public-key systems rely on the fact that solving for x (a discrete logarithm) appears hard classically in the right groups.\n\nRSA is built on arithmetic modulo N=pq. The group structure (and Euler\u2019s theorem) explains why encryption and decryption are inverses when keys are chosen correctly.\n\nYou don\u2019t need to memorize theorems yet, but you do need intuition: mod arithmetic creates a finite world where some operations are easy forward but hard to invert \u2014 and that asymmetry is the engine of public-key crypto.`,
      keyPoints:['a \u2261 b (mod n) means they differ by a multiple of n','Operations wrap around in \u007b0..n-1\u007d','Fast exponentiation makes huge powers feasible','Public-key crypto uses easy-forward/hard-inverse structure','RSA arithmetic happens modulo N=pq'],
      analogy:`A 12-hour clock: 3 hours after 11 o'clock isn't 14, it's 3. The numbers wrap around a fixed size. That wrapping is exactly mod arithmetic.`,
      res:[['↗ Khan: Modular arithmetic','https://www.khanacademy.org/computing/computer-science/cryptography/modarithmetic/a/what-is-modular-arithmetic']],
      steps:['Compute 17 mod 5. (Answer: 2)','Compute 23 mod 7, and 100 mod 9.','Understand: cryptography uses mod with 600-digit numbers.','Try: (7 × 8) mod 10 = ?'],
      exercise:{
        prompt:`Compute <code>(a * b) mod n</code>. Input: three integers <code>a b n</code>. Return result in <code>0..n-1</code>.`,
        starter:`function solve(input) {\n  const [a,b,n] = input.trim().split(/\\s+/).map(Number);\n  return '';\n}\n`,
        tests:[
          { input: '7 8 10', expected: '6' },
          { input: '17 1 5', expected: '2' },
          { input: '2 3 7', expected: '6' }
        ],
        solution:`function solve(input){const [a,b,n]=input.trim().split(/\\s+/).map(Number);let r=(a*b)%n;r=((r%n)+n)%n;return String(r);}`
      },
      flashcards:[{q:'What is 17 mod 5?',a:'2 (remainder after division).'},{q:'Why does RSA use mod arithmetic?',a:'Operations wrap in a finite set; inverse problems can be hard.'}],
      game:null,
      quiz:{q:'What is 17 mod 5?',opts:['3','2','12','5'],correct:1,ok:'17 = 3×5 + 2, so 17 mod 5 = 2. This wrapping is the core of RSA math.',no:'17 divided by 5 is 3 remainder 2. So 17 mod 5 = 2.'}}
    ,{id:'t17',title:'Entropy & information',
      learn:`<b>Entropy</b> measures unpredictability — how much "surprise" or information something carries. A fair coin has 1 bit of entropy; a loaded coin has less. In cryptography, entropy measures how hard a key is to guess. High entropy = strong key. This idea (from Claude Shannon) underpins all of security.`,
      deep:`In security, entropy is a way to talk about guessing difficulty. If a key is uniformly random among N possibilities, then it has log\u2082(N) bits of entropy. For example, 8 fair coin flips give N=2\u2078 possibilities and 8 bits of entropy.\n\nReal systems fail when entropy assumptions are wrong: human-chosen passwords have far less entropy than they appear; poorly-seeded random number generators can collapse security entirely; and repeated nonces can break protocols even if the underlying cipher is perfect.\n\nTwo practical ideas matter: <b>min-entropy</b> (worst-case unpredictability) and <b>entropy extraction</b> (turning messy, biased randomness into near-uniform bits). Many \u201crandomness\u201d sources are biased; secure systems use construction like HKDF and proper seeding to stabilize them.\n\nThis connects directly to quantum security: QRNG can provide high-quality entropy, but it must still be integrated correctly (health tests, extraction, safe distribution). Entropy is the foundation under every key, signature nonce, and ephemeral secret.`,
      keyPoints:['Uniform N choices gives log2(N) bits of entropy','Low-entropy human secrets are a common failure mode','Min-entropy captures worst-case guessability','Entropy extraction turns biased bits into near-uniform keys','Bad randomness breaks systems even with perfect algorithms'],
      analogy:`A password "0000" has almost no entropy — easy to guess. A random 20-character password has high entropy — a haystack so big no one finds the needle. Entropy is the size of the haystack.`,
      res:[],
      steps:['Understand: entropy = unpredictability = bits of security.','A fair coin = 1 bit. 8 coins = 8 bits = 256 possibilities.','Realize: a good key must have high entropy (be truly random).','Connect this to why QRNG matters later.','Play Entropy Meter game →'],
      game:'entropy',
      quiz:{q:'In crypto, what does high entropy mean for a key?',opts:['It is short','It is hard to guess (strong)','It is fast','It is reusable'],correct:1,ok:'High entropy = highly unpredictable = hard to guess = strong key.',no:'High entropy means highly unpredictable — a strong, hard-to-guess key.'}}

  ]},

  L2:{icon:'🐍',tag:'Level 2',name:'Code It in Python',desc:'Build a real quantum simulator from scratch',color:'lime',topics:[
    {id:'t21',title:'Python setup & first program',
      learn:`Python runs every quantum framework — Qiskit, Cirq, PennyLane. You just need comfort, not mastery.`,
      deep:`Even if you end up specializing in PQC (mostly C/Rust) or governance (mostly policy), Python is the fastest way to prototype crypto experiments, parse data, and reproduce papers. For quantum computing education, Python is the default because toolchains like Qiskit/Cirq/PennyLane expose circuits and simulators via Python.\n\nIn this app, we don’t execute Python in the browser. Instead, exercises use a tiny JavaScript sandbox to practice the same reasoning: functions, arrays/vectors, and basic math. Treat it as “Python concepts, checked in JS.”\n\nYour goal in Level 2 isn’t to become a professional software engineer — it’s to be able to run snippets, manipulate vectors/matrices, and understand what a framework is doing under the hood.\n\nIf you can read a short script, edit a constant, run it, and interpret the output, you’re ready for the rest of the academy.`,
      keyPoints:['Python is the default for quantum learning frameworks','You only need comfort: run/edit/interpret small scripts','We’ll practice the same concepts with in-browser JS exercises','Level 2 is about building intuition for simulators'],
      analogy:`Python is your workbench. Learn where the tools are before building circuits.`,
      res:[['↗ Download Python','https://www.python.org/downloads/'],['↗ Free book Ch.1','https://automatetheboringstuff.com/3e/chapter1.html']],
      steps:['Install Python 3.12.','Terminal: python3 --version.','Type 2+2 in the shell, get 4.','Read Automate Ch.1, type every example.'],
      exercise:{
        prompt:`Write <b>solve(input)</b> that reads two numbers and returns their sum.\n<br/><br/>Example input: <code>2 3</code> → output: <code>5</code>`,
        starter:`function solve(input) {\n  // input: string like \"2 3\" or \"2\\n3\"\n  // return: the sum as a string\n  return \"\";\n}\n`,
        tests:[
          { input: '2 3', expected: '5' },
          { input: '10\n20', expected: '30' },
          { input: '0 0', expected: '0' },
          { input: '-5 8', expected: '3' }
        ],
        solution:`function solve(input){const a=input.trim().split(/\\s+/).map(Number);return String((a[0]||0)+(a[1]||0));}`
      },
      game:null,
      quiz:{q:'0.8 ** 2 in Python gives?',opts:['1.6','0.64','0.8','0.16'],correct:1,ok:'** is power. 0.64 — a measurement probability!',no:'** = power: 0.8×0.8=0.64.'}},
    {id:'t22',title:'NumPy — matrix math in code',
      learn:`<b>NumPy</b> does vector/matrix math instantly. Your Level 1 math, now in code. Simulators use exactly this.`,
      deep:`NumPy represents vectors as arrays and matrices as 2D arrays. The key operation is matrix-vector multiplication. In Python you’ll often see @ for matrix multiply: <code>U @ ψ</code>. That’s exactly what a quantum gate does: apply a unitary matrix U to a state vector ψ.\n\nThis topic’s code block is intentionally tiny. The big picture is: state = array, gate = array, evolution = matrix multiply. Once that feels natural, you can understand (and trust) what higher-level libraries are doing.\n\nIn exercises we’ll mimic this idea in JavaScript arrays: representing a qubit as [a,b] and applying gates like X/H/Z by computing new arrays.\n\nIf you can implement a Hadamard transform and compute probabilities, you can build a toy simulator — which is enough to understand Shor/Grover at a conceptual level.`,
      keyPoints:['Vector = array, gate = matrix, evolution = multiply','Qiskit/Cirq do the same thing at scale','Practice gates with arrays in exercises','Probabilities come from squared magnitudes'],
      analogy:`A calculator for matrices. A page of work becomes one line.`,
      res:[['↗ NumPy Quickstart','https://numpy.org/doc/stable/user/quickstart.html']],
      steps:['pip install numpy','Run the code below.','Build the Hadamard gate, apply to [1,0].'],
      exercise:{
        prompt:`Implement <b>solve(input)</b> that applies the X gate to a 2-number vector.\n<br/><br/>Input: two numbers <code>a b</code> representing [a,b]. Output the new vector after X: <code>b a</code>.`,
        starter:`function solve(input) {\n  const [a,b] = input.trim().split(/\\s+/).map(Number);\n  // TODO: apply X gate\n  return \"\";\n}\n`,
        tests:[
          { input: '1 0', expected: '0 1' },
          { input: '0 1', expected: '1 0' },
          { input: '3 5', expected: '5 3' }
        ],
        solution:`function solve(input){const [a,b]=input.trim().split(/\\s+/).map(Number);return \`\${b} \${a}\`;}`
      },
      code:`<span class="ck">import</span> numpy <span class="ck">as</span> np
X=np.<span class="cf">array</span>([[<span class="cn">0</span>,<span class="cn">1</span>],[<span class="cn">1</span>,<span class="cn">0</span>]])
q0=np.<span class="cf">array</span>([<span class="cn">1</span>,<span class="cn">0</span>])
<span class="cf">print</span>(X @ q0)  <span class="cc"># [0 1] = |1⟩</span>`,
      game:'gate',
      quiz:{q:'H@q0=[0.707,0.707]. P(0)?',opts:['0.707','0.5','1.0','0.25'],correct:1,ok:'0.707²≈0.5. Superposition!',no:'Square it: 0.707²≈0.5.'}},
    {id:'t23',title:'Build your own simulator',
      learn:`You can now build a <b>quantum simulator</b> with just NumPy — states as vectors, gates as matrices, measurement by squaring. This is Qiskit's core.`,
      deep:`A “simulator” is just deterministic math that produces the same distributions as quantum measurement would. It does not magically make quantum hardware. But it is incredibly valuable for learning, debugging, and understanding algorithms.\n\nFor a single qubit, simulation is just repeated application of 2×2 matrices. For multiple qubits, the state vector has length 2ⁿ and gates are 2ⁿ×2ⁿ (or structured operators embedded into that space). The cost grows exponentially, which is why simulating 40–50 qubits becomes hard.\n\nA key conceptual trick: many gates don’t change probabilities directly — they change <b>phase</b>, which only becomes visible later through interference. That’s why your simulator should track complex numbers (or at least signed reals in toy cases).\n\nIf you implement H, X, Z, and a measurement function in code, you’ll understand 90% of what beginner quantum frameworks are doing under the hood.`,
      keyPoints:['Simulators reproduce quantum probability distributions via math','State size is 2^n for n qubits (exponential scaling)','Phases matter: some gates change phase, not probability','H/X/Z + measurement is a complete learning toolkit'],
      analogy:`A toy engine to understand the real one.`,
      res:[],
      steps:['Save the code as mysim.py.','Run it.','Add Z gate [[1,0],[0,-1]] on |1⟩ — probabilities unchanged (phase = interference seed).'],
      exercise:{
        prompt:`Implement <b>solve(input)</b> that applies the Hadamard gate to |0⟩.\n<br/><br/>Output the probabilities P0 and P1 as <code>P0=0.50 P1=0.50</code>.`,
        starter:`function solve(input) {\n  // Ignore input. Start with |0> = [1,0]\n  // H|0> = [1/sqrt(2), 1/sqrt(2)]\n  // Return: \"P0=0.50 P1=0.50\"\n  return \"\";\n}\n`,
        tests:[
          { input: '', expected: 'P0=0.50 P1=0.50' }
        ],
        solution:`function solve(){const k=1/Math.sqrt(2);const a=k,b=k;const p0=(a*a).toFixed(2),p1=(b*b).toFixed(2);return \`P0=\${p0} P1=\${p1}\`;}`
      },
      code:`<span class="ck">import</span> numpy <span class="ck">as</span> np
zero=np.<span class="cf">array</span>([<span class="cn">1</span>,<span class="cn">0</span>])
H=np.<span class="cf">array</span>([[<span class="cn">1</span>,<span class="cn">1</span>],[<span class="cn">1</span>,-<span class="cn">1</span>]])/np.<span class="cf">sqrt</span>(<span class="cn">2</span>)
<span class="ck">def</span> <span class="cf">m</span>(s):<span class="cf">print</span>(<span class="cs">f"P0={s[0]**2:.2f}"</span>)
<span class="cf">m</span>(H @ zero)  <span class="cc"># 50/50</span>`,
      game:null,
      quiz:{q:'Squaring amplitudes gives?',opts:['Next gate','Measurement probabilities','Bigger vector','Qubit name'],correct:1,ok:'Amplitude²=probability. The Born rule in code.',no:'It gives measurement probabilities.'}}
  ]},

  L3:{icon:'⚛️',tag:'Level 3',name:'Quantum Mechanics',desc:'Superposition, entanglement, the Bloch sphere',color:'violet',topics:[
    {id:'t31',title:'Superposition',
      learn:`A qubit in <b>superposition</b> is genuinely 0 AND 1 at once — made by the Hadamard gate. Measuring collapses it randomly. Algorithms exploit "all states at once."`,
      deep:`Superposition is not “unknown classical bits” — it is a single state vector with amplitudes for 0 and 1. The Hadamard gate creates equal superposition from |0⟩.\n\nCrucially, you cannot read out both amplitudes directly in one measurement — you get one bit. Quantum algorithms use interference so that wrong paths cancel and right paths reinforce before measurement.\n\nFor security learners: superposition enables QKD and quantum algorithms, but also explains why simulation scales as 2^n.`,
      keyPoints:['Superposition = vector with amplitudes for 0 and 1','Measurement yields one random bit','Hadamard creates equal superposition from |0⟩','Algorithms need interference, not just superposition'],
      flashcards:[{q:'What gate creates equal superposition from |0⟩?',a:'Hadamard (H).'},{q:'What happens when you measure a superposition?',a:'It collapses to 0 or 1 with Born-rule probabilities.'}],
      analogy:`A spinning coin — both heads and tails until it lands.`,
      res:[['↗ Quantum Country','https://quantum.country/qcvc'],['↗ IBM Learning','https://quantum.cloud.ibm.com/learning']],
      steps:['Read the Quantum Country essay.','Measure H|0⟩ 1000× in your sim, count results.','Sign up free at IBM Quantum.'],
      game:'coin',
      quiz:{q:'Why is superposition useful?',opts:['Faster bits','Explores many states, interference picks the answer','More memory','Certain results'],correct:1,ok:'Superposition + interference: explore all, amplify the right one.',no:'It\'s superposition AND interference working together.'}},
    {id:'t32',title:'The Bloch sphere',
      learn:`Every single-qubit state can be drawn as a point on a <b>sphere</b> — the Bloch sphere. North pole = |0⟩, south = |1⟩, the equator = superpositions. Gates are rotations of this sphere. It's the single most useful mental picture in quantum computing.`,
      analogy:`Like a globe where your qubit is a pin. The X gate spins it 180° around one axis; H rotates it to the equator. Visualizing helps everything click.`,
      res:[['↗ IBM: Bloch sphere','https://quantum.cloud.ibm.com/learning']],
      steps:['Picture |0⟩ at the north pole.','Apply H mentally: pin moves to the equator (superposition).','Rotate the Bloch Sphere game and watch gates move the point →'],
      game:'bloch',
      quiz:{q:'On the Bloch sphere, what sits at the poles?',opts:['Superpositions','|0⟩ and |1⟩','Entangled states','Nothing'],correct:1,ok:'North=|0⟩, South=|1⟩. The equator holds equal superpositions.',no:'Poles = |0⟩ (north) and |1⟩ (south). Equator = superpositions.'}},
    {id:'t33',title:'Entanglement',
      learn:`<b>Entanglement</b> links qubits so measuring one fixes the other instantly. A Bell pair always matches. This powers QKD — eavesdroppers get caught.`,
      analogy:`Two magic gloves in sealed boxes worldwide. Open yours = left, you instantly know the other is right. Neither decided until opened.`,
      res:[['↗ Run on IBM hardware','https://quantum.cloud.ibm.com/learning']],
      steps:['pip install qiskit','Run the Bell state code (H then CNOT).','Measure 10× — always matching. That\'s entanglement.'],
      code:`<span class="ck">from</span> qiskit <span class="ck">import</span> QuantumCircuit
qc=<span class="cf">QuantumCircuit</span>(<span class="cn">2</span>)
qc.<span class="cf">h</span>(<span class="cn">0</span>); qc.<span class="cf">cx</span>(<span class="cn">0</span>,<span class="cn">1</span>)  <span class="cc"># entangle</span>`,
      game:'entangle',
      quiz:{q:'Why does entanglement matter for QKD?',opts:['Faster encryption','Stores key twice','Eavesdropper measuring it leaves detectable traces','Instant data'],correct:2,ok:'Measurement is irreversible — interception is detectable.',no:'You can\'t measure it without disturbing it — that\'s detectable.'}},
    {id:'t34',title:'Multi-qubit systems',
      learn:`Two qubits have <b>four</b> possible states (00,01,10,11), described by a 4-number vector. Three qubits = 8 states. n qubits = 2ⁿ. This exponential growth is why quantum computers are powerful — and why simulating them classically is so hard.`,
      analogy:`Each qubit you add doubles the space. 300 qubits = more states than atoms in the universe. That's the power and the difficulty.`,
      res:[],
      steps:['List all 4 states of a 2-qubit system.','Realize 10 qubits = 1024 states tracked at once.','Compute 2ⁿ for n=20 (over a million!).'],
      game:null,
      quiz:{q:'How many states does a 4-qubit system have?',opts:['4','8','16','32'],correct:2,ok:'2⁴=16. Each qubit doubles the space — exponential power.',no:'2ⁿ where n=4: 2⁴=16 states.'}},
    {id:'t35',title:'Measurement & decoherence',
      learn:`Quantum states are fragile. <b>Measurement</b> collapses superposition to one value. <b>Decoherence</b> is when the environment accidentally "measures" a qubit, destroying its quantum behavior. This is the central engineering challenge of quantum computing — and why real hardware has errors.`,
      analogy:`Superposition is like a delicate soap bubble. Measuring (or noise) pops it. Keeping bubbles intact long enough to compute is the hard part.`,
      res:[['↗ IBM hardware','https://quantum.cloud.ibm.com/']],
      steps:['Understand: measurement = irreversible collapse.','Decoherence = unwanted measurement by the environment.','This is why qubits need extreme cold and isolation.'],
      game:null,
      quiz:{q:'What is decoherence?',opts:['A type of gate','Environment destroying quantum behavior','A measurement result','A kind of qubit'],correct:1,ok:'Right — the environment "measures" the qubit, collapsing it. The big engineering challenge.',no:'Decoherence: the environment disturbs the qubit, destroying superposition.'}}
    ,{id:'t36',title:'Quantum error correction',
      learn:`Qubits are noisy and fragile (decoherence). <b>Quantum error correction</b> spreads one "logical" qubit across many physical qubits, so errors can be detected and fixed without measuring (and destroying) the data. This is why useful quantum computers need millions of physical qubits — and why breaking RSA is still years away.`,
      analogy:`Like writing an important message three times — if one copy smudges, the other two outvote it. QEC does this for qubits, but cleverly, without ever reading the message directly.`,
      res:[['↗ IBM: error correction','https://quantum.cloud.ibm.com/learning']],
      steps:['Understand: physical qubits are error-prone.','One logical qubit = many physical qubits working together.','This is why scaling quantum computers is so hard.','Connect: this delays the quantum threat to crypto.'],
      game:null,
      quiz:{q:'Why does quantum error correction matter for security timelines?',opts:['It speeds up encryption','Shor needs millions of error-corrected qubits — hardware is not there yet','It makes qubits cheaper','It replaces QKD'],correct:1,ok:'QEC overhead means cryptographically relevant machines are still far off — but HNDL means migration cannot wait.',no:'QEC needs many physical qubits per logical one — Shor-scale machines are years away, yet long-lived data is at risk today.'}}

  ]},

  L4:{icon:'🔁',tag:'Level 4',name:'Circuits & Algorithms',desc:'Gates, circuits, Deutsch-Jozsa, Shor, Grover',color:'pink',topics:[
    {id:'t41',title:'Quantum circuits',
      learn:`A <b>quantum circuit</b> is a sequence of gates applied to qubits, read left to right, ending in measurement. It's the "program" of a quantum computer. You draw them as horizontal lines (qubits) with gate boxes.`,
      deep:`A circuit is a <b>composition of operators</b>. If your state is |\u03c8\u27e9 and you apply gates U then V, the final state is VU|\u03c8\u27e9 (note the right-to-left application in math even though diagrams read left-to-right). This is just function composition.\n\nCircuits often include <b>controlled operations</b> (like CNOT), which create entanglement and let algorithms correlate qubits. Measurements typically happen at the end because measurement collapses the state and turns quantum data into classical bits. Some protocols do mid-circuit measurement, but you can think of that as intentionally collapsing part of the system.\n\nA critical engineering detail: real hardware has limited connectivity and gate sets. Compilers translate your abstract circuit into a device-specific sequence of native gates, inserting swaps and decompositions. This overhead affects cryptanalysis timelines (resource estimates) and is one reason theoretical \u201cqubit counts\u201d don\u2019t directly translate to real attacks.\n\nFor security, the circuit model matters because Shor/Grover are described as circuits with specific depth and gate counts. Defensive planning uses these metrics to estimate the feasibility of breaking deployed cryptosystems.`,
      keyPoints:['Circuit = composition of linear operators (unitaries)','Controlled gates (e.g. CNOT) enable entanglement','Measurement collapses quantum state into classical bits','Real devices require compiling to native gates/connectivity','Security timelines depend on circuit depth and gate counts'],
      analogy:`Sheet music for qubits: each line is a qubit, each symbol a gate played in order.`,
      res:[['↗ IBM Composer','https://quantum.cloud.ibm.com/']],
      steps:['Draw a circuit: H on qubit 0, then measure.','Add a CNOT to entangle two qubits.','Build it visually in IBM Quantum Composer.'],
      game:'gate',
      quiz:{q:'How do you read a quantum circuit?',opts:['Right to left','Left to right, ending in measurement','Top to bottom','Randomly'],correct:1,ok:'Left to right, measurement last — like reading a program.',no:'Left to right, ending in measurement.'}},
    {id:'t42',title:'Your first algorithm (Deutsch)',
      learn:`The <b>Deutsch algorithm</b> is the simplest proof quantum beats classical. It determines a property of a function in ONE query where classical needs TWO. Tiny, but it proves the principle: quantum parallelism is real.`,
      deep:`Deutsch (and Deutsch\u2013Jozsa) is about a black-box function f:\u007b0,1\u007d\u2192\u007b0,1\u007d and deciding whether it is constant or balanced. Classically you must query f(0) and f(1) to be sure. Quantumly, you prepare a superposition, query once, and use interference so the answer becomes visible in a measurement.\n\nThe key mechanism is <b>phase kickback</b>: by putting the output qubit in (|0\u27e9\u2212|1\u27e9)/\u221a2, the oracle effectively writes (-1)<sup>f(x)</sup> as a phase on the input state. That phase then interferes under a final Hadamard.\n\nDeutsch is not \u201cuseful\u201d industrially, but it is the cleanest demonstration of the core idea: quantum algorithms often convert a property of f into a phase pattern, then use interference to extract that property with fewer queries.\n\nFor security learners, it trains the instinct that \u201cquantum advantage\u201d often comes from <b>structured interference</b>, not just \u201ctrying all answers\u201d.`,
      keyPoints:['Problem: decide constant vs balanced with minimal queries','Quantum uses phase kickback to encode f(x) into phase','Interference + Hadamard reveals the property','Not practical itself, but foundational intuition','Quantum advantage often = structured phase + interference'],
      analogy:`Like identifying if a coin is two-headed or normal with a single look instead of checking both sides. A small win that proves the concept.`,
      res:[['↗ IBM: Deutsch-Jozsa','https://quantum.cloud.ibm.com/learning']],
      steps:['Understand the setup: a "black box" function.','Classical: needs 2 checks. Quantum: 1.','Run the Deutsch-Jozsa tutorial on IBM.'],
      game:null,
      quiz:{q:'What does the Deutsch algorithm prove?',opts:['Quantum is always faster','Quantum can beat classical query count','Encryption is broken','Qubits are cheap'],correct:1,ok:'It proves quantum parallelism gives a real query advantage — the first such proof.',no:'It proves quantum can solve a problem in fewer queries than classical.'}},
    {id:'t43',title:"Shor's algorithm",
      learn:`<b>Shor's algorithm</b> reduces factoring and discrete logarithms to <b>period finding</b> (of <code>a<sup>x</sup> mod N</code>), then uses the <b>quantum Fourier transform (QFT)</b> to extract the period from a superposition. That breaks <b>RSA</b> (factoring), <b>Diffie-Hellman</b>, and <b>ECC</b> (discrete log) — the public-key algorithms behind HTTPS and most PKI. Symmetric ciphers like AES are not broken this way (Grover is the separate threat there).`,
      deep:`Shor reduces factoring to a <b>period-finding</b> problem. Pick a random a < N and consider the function f(x)=a<sup>x</sup> mod N. If you can find its period r (the smallest r such that a<sup>r</sup>\u22611 mod N), number theory lets you compute nontrivial factors of N with high probability.\n\nThe quantum part is: create a superposition over x, compute f(x) into a second register, then apply the <b>quantum Fourier transform (QFT)</b> to extract information about r from the phase structure. Measuring yields a value close to k/r for some k, and classical continued fractions recovers r.\n\nImportant nuance for defenders: the \u201cShor breaks RSA\u201d headline hides big engineering costs. Implementing modular exponentiation reversibly dominates the circuit cost. Error correction overhead and gate fidelity determine whether the attack is feasible.\n\nStill, the security conclusion is binary: RSA/ECC/DH rely on problems Shor solves in polynomial time. Once cryptographically-relevant quantum computers exist, these schemes cannot be defended by parameter tuning; they must be replaced.`,
      keyPoints:['Shor reduces factoring to period-finding of a^x mod N','QFT extracts period information from superposition','Classical continued fractions recovers r from measurements','Modular exponentiation dominates real circuit cost','RSA/ECC/DH must be replaced (not just \u201cbigger keys\u201d)'],
      analogy:`RSA is a padlock whose combo is two giant primes multiplied. Shor's is a machine that factors the product back to the combo — opening every RSA lock.`,
      res:[['↗ IBM: Shor (search)','https://quantum.cloud.ibm.com/learning']],
      steps:['Understand: RSA = factoring is hard.','Shor finds factors via period-finding + quantum Fourier transform.','Run the Shor tutorial (factors 15!).','Be Shor yourself in the Factor game →'],
      exercise:{
        prompt:`Shor uses modular exponentiation. Compute <code>a^e mod n</code> for small integers.\nInput: <code>a e n</code> (e ≥ 0).`,
        starter:`function solve(input) {\n  const [a,e,n] = input.trim().split(/\\s+/).map(Number);\n  // return a^e mod n as string\n  return '';\n}\n`,
        tests:[
          { input: '2 3 7', expected: '1' },
          { input: '3 4 7', expected: '4' },
          { input: '7 2 15', expected: '4' }
        ],
        solution:`function solve(input){const [a,e,n]=input.trim().split(/\\s+/).map(Number);let r=1,b=a%n;let exp=e;while(exp>0){if(exp%2===1)r=(r*b)%n;b=(b*b)%n;exp=Math.floor(exp/2);}r=((r%n)+n)%n;return String(r);}`
      },
      flashcards:[{q:'What problem does Shor solve?',a:'Period finding (via QFT) — breaks RSA, DH, and ECC.'},{q:'What classical step recovers the period?',a:'Continued fractions after measurement.'}],
      game:'factor',
      quiz:{q:'What does Shor\'s algorithm break, and how?',opts:['AES, by brute force','RSA, DH, and ECC via period-finding + QFT (factoring / discrete log)','Hashing, by collision','QKD, by measurement'],correct:1,ok:'Shor solves period finding with QFT — breaking factoring and discrete log, so RSA/DH/ECC fall.',no:'Shor uses period finding + QFT to attack factoring and discrete log — RSA, DH, and ECC.'}},
    {id:'t44',title:"Grover's algorithm",
      learn:`<b>Grover's algorithm</b> searches N unsorted items in √N steps (quadratic speedup). It weakens symmetric crypto: AES-128 effectively becomes 64-bit security. The fix is simple — double key sizes (use AES-256).`,
      deep:`Grover is an <b>amplitude amplification</b> algorithm. It assumes an oracle that can recognize solutions (mark them with a phase flip). Starting from an equal superposition, Grover alternates two reflections: (1) flip the phase of marked states, and (2) reflect about the average amplitude. This rotates the state vector in a 2D subspace, increasing the probability of measuring a marked state.\n\nIf there is one solution among N items, about (\u03c0/4)\u221aN iterations maximize success probability. If there are multiple solutions, the optimal iteration count changes; over-rotating reduces success, which is why tuning matters.\n\nFor cryptography, Grover translates to brute-force search of a key space. A k-bit key space of size 2<sup>k</sup> becomes ~2<sup>k/2</sup> work under Grover. That\u2019s why AES-128 (2<sup>128</sup>) becomes ~2<sup>64</sup> effective.\n\nReal-world caveat: Grover is not \u201cfree.\u201d Each iteration is a big reversible circuit. But the conservative defense is easy: use AES-256 and appropriate hash sizes so even quadratic speedups remain infeasible.`,
      keyPoints:['Grover = amplitude amplification using reflections','Needs an oracle that marks solutions via phase flip','~(\u03c0/4)\u221aN iterations for one solution','k-bit brute force becomes ~2^{k/2} work','Defense: double key sizes (AES-256, larger hashes)'],
      analogy:`Finding a name in an unsorted phonebook: classical reads all N entries, Grover needs only √N. For a million entries, 1000 instead of a million.`,
      res:[['↗ IBM: Grover (search)','https://quantum.cloud.ibm.com/learning']],
      steps:['Understand √N vs N speedup.','AES-128 → effective 64-bit under Grover.','Fix: AES-256. Run the Grover tutorial.','Play the Grover Search game →','Then implement a tiny oracle + diffusion step in the Exercise tab →'],
      game:'grover',
      exercise:{
        prompt:`Implement <b>solve(input)</b> to run <b>one Grover iteration</b> on a 2-qubit state.\n<br/><br/>We represent amplitudes as a 4-number array <code>a0 a1 a2 a3</code>.\n- The <b>oracle</b> marks index <code>m</code> by flipping its sign.\n- The <b>diffusion</b> step maps each amplitude <code>x</code> to <code>2·avg - x</code>, where avg is the mean of the 4 amplitudes.\n<br/><br/>Input format: first an integer mark index <code>m</code> (0..3), then 4 amplitudes.\nReturn the 4 new amplitudes separated by spaces (use normal JS numbers).`,
        starter:`function solve(input) {\n  const parts = input.trim().split(/\\s+/).map(Number);\n  const m = parts[0];\n  let amps = parts.slice(1, 5);\n  // TODO: oracle: flip sign at index m\n  // TODO: diffusion: amps[i] = 2*avg - amps[i]\n  return '';\n}\n`,
        tests:[
          { input: '2 0.5 0.5 0.5 0.5', expected: '0 0 1 0' },
          { input: '3 0.5 0.5 0.5 0.5', expected: '0 0 0 1' }
        ],
        solution:`function solve(input){const p=input.trim().split(/\\s+/).map(Number);const m=p[0];let a=p.slice(1,5);a[m]=-a[m];const avg=(a[0]+a[1]+a[2]+a[3])/4;a=a.map(x=>2*avg-x);return a.join(' ');}`
      },
      quiz:{q:'Grover\'s effect on AES-128?',opts:['Fully broken','Effective security ~64-bit; use AES-256','No effect','Instant crack'],correct:1,ok:'√(2¹²⁸)=2⁶⁴. Weakened but fixable with AES-256.',no:'Quadratic speedup → ~64-bit effective. Use AES-256.'}}
  ]},

  L5:{icon:'🔑',tag:'Level 5',name:'Classical Cryptography',desc:'Symmetric, asymmetric, PKI, TLS — the full stack you must defend',color:'amber',topics:[
    {id:'t51',title:'Symmetric vs asymmetric',
      learn:`Two families. <b>Symmetric</b> (AES): one shared key for lock+unlock, fast, but how do you share the key? <b>Asymmetric</b> (RSA, ECC): a public key locks, a private key unlocks — solves key sharing. Quantum threatens these differently: Shor kills asymmetric, Grover dents symmetric.`,
      analogy:`Symmetric = one key both people copy. Asymmetric = a mailbox anyone can drop into (public) but only you can open (private).`,
      res:[['↗ Crypto I (audit free)','https://www.coursera.org/learn/crypto']],
      steps:['List: AES=symmetric, RSA/ECC=asymmetric.','Understand the key-sharing problem symmetric has.','Note: quantum hits these two families differently.'],
      game:null,
      quiz:{q:'Which does Shor\'s algorithm destroy?',opts:['Symmetric (AES)','Asymmetric (RSA, DH, ECC)','Both equally','Neither'],correct:1,ok:'Shor kills asymmetric (RSA/DH/ECC). Grover only dents symmetric.',no:'Shor breaks asymmetric crypto — RSA, Diffie-Hellman, and ECC.'}},
    {id:'t52',title:'How RSA actually works',
      learn:`RSA: pick two big primes, multiply them (easy). The product is public; the primes are secret. Security = factoring the product is infeasible classically. Encryption/signatures use modular exponentiation with these keys. Shor's algorithm factors the product → game over.`,
      analogy:`Mixing two paint colors is easy; un-mixing to find the originals is hard. RSA multiplies primes (easy) betting nobody can factor back (hard) — until Shor.`,
      res:[['↗ Dan Boneh lectures','https://crypto.stanford.edu/~dabo/courses/OnlineCrypto/']],
      steps:['Two primes p,q → N=p×q is public.','Factoring N back to p,q is the hard problem.','Watch Boneh\'s RSA lecture. Then attack RSA in the game →'],
      exercise:{
        prompt:`Compute GCD of two positive integers (Euclidean algorithm). Input: <code>a b</code>.`,
        formatExample:'Return the GCD as a string, e.g. "6"',
        hints:['While b > 0, replace (a,b) with (b, a mod b).','When b is 0, a is the GCD.'],
        starter:`function solve(input) {\n  let [a,b] = input.trim().split(/\\s+/).map(Number);\n  return '';\n}\n`,
        tests:[
          { input: '48 18', expected: '6' },
          { input: '17 5', expected: '1' },
          { input: '270 192', expected: '6' }
        ],
        solution:`function solve(input){let [a,b]=input.trim().split(/\\s+/).map(Number);while(b>0){const t=b;b=a%b;a=t;}return String(a);}`
      },
      game:'rsa',
      quiz:{q:'RSA\'s security depends on what being hard?',opts:['Adding numbers','Factoring large numbers','Sorting lists','Drawing graphs'],correct:1,ok:'Factoring the product of two large primes. Shor makes it easy.',no:'Factoring large numbers into primes. Exactly what Shor defeats.'}},
    {id:'t53',title:'Hashing & integrity',
      learn:`A <b>hash</b> (like SHA-256) turns any data into a fixed fingerprint. Change one bit, the fingerprint changes completely. Used for passwords, integrity checks, signatures. Grover gives a mild speedup against hashes, so post-quantum guidance favors larger hashes (SHA-384/512).`,
      analogy:`A blender that turns any meal into a unique smoothie color you can't un-blend. Same meal = same color; any change = totally different color.`,
      res:[],
      steps:['Understand: hash = one-way fingerprint.','Tiny input change = huge output change (avalanche).','Quantum: use SHA-384+ for margin.'],
      game:null,
      quiz:{q:'What is a cryptographic hash?',opts:['Reversible encryption','A one-way fixed-size fingerprint of data','A type of key','A random number'],correct:1,ok:'One-way fingerprint — easy forward, infeasible to reverse.',no:'A one-way fingerprint: any data → fixed-size unique output.'}},
    {id:'t54',title:'Key exchange (Diffie-Hellman)',
      learn:`<b>Diffie-Hellman</b> lets two strangers create a shared secret over a public channel, without ever sending the secret itself. It underpins HTTPS. Its security rests on the discrete logarithm problem — which Shor's algorithm also breaks. So DH and ECC fall to quantum just like RSA.`,
      analogy:`Two people mix secret paint colors with a shared public color, swap the mixes, then add their own secret again — ending with the same blend an eavesdropper can't reproduce.`,
      res:[['↗ Crypto I','https://www.coursera.org/learn/crypto']],
      steps:['Understand: shared secret over public channel.','Security = discrete logarithm hardness.','Shor breaks discrete log too → DH/ECC vulnerable.'],
      game:null,
      quiz:{q:'Why are Diffie-Hellman and ECC quantum-vulnerable?',opts:['They use weak keys','Shor breaks the discrete log they rely on','They are too slow','They use hashing'],correct:1,ok:'Shor solves discrete log as well as factoring — so DH/ECC fall too.',no:'Shor breaks the discrete logarithm problem underpinning them.'}},
    {id:'t55',title:'AES & symmetric encryption',
      learn:`<b>AES</b> (Advanced Encryption Standard) is the workhorse of modern security — disk encryption, VPNs, TLS bulk data. One shared secret key encrypts and decrypts. It's fast and battle-tested. Quantum's <b>Grover</b> algorithm gives a quadratic speedup, so AES-128's effective strength drops to ~64 bits. The fix is straightforward: <b>use AES-256</b>, which stays well above safe margins post-quantum.`,
      deep:`AES operates on 128-bit blocks with key sizes 128/192/256 bits. Modes like <b>GCM</b> add authentication (AEAD). In TLS, symmetric crypto encrypts the actual data after the handshake establishes keys. Post-quantum planning: inventory every AES-128 deployment and upgrade to 256 where long-term confidentiality matters.`,
      keyPoints:['Symmetric = one shared key','Grover halves effective key bits','AES-256 is the post-quantum recommendation','Used inside TLS after key exchange'],
      analogy:`AES is the armored truck carrying the payload. The key exchange (RSA/Kyber) is how you hand off the truck keys — Grover picks cheaper locks, not the truck design.`,
      res:[['↗ NIST AES spec','https://csrc.nist.gov/projects/cryptographic-standards-and-guidelines'],['↗ Crypto I (Coursera)','https://www.coursera.org/learn/crypto']],
      steps:['List where you use encryption: HTTPS, disk, Wi-Fi, messaging.','Identify AES-128 vs AES-256 in each.','Plan upgrades: AES-128 → AES-256 for 10+ year data.','Play the Grover Search game →'],
      exercise:{
        prompt:`Grover halves effective symmetric key bits. Input: key size in bits (integer k). Return effective bits after Grover.`,
        formatExample:'Return an integer as a string, e.g. "64" for k=128',
        hints:['Effective bits ≈ k / 2 (floor).','AES-128 → 64 effective.'],
        starter:`function solve(input) {\n  const k = Number(input.trim());\n  return '';\n}\n`,
        tests:[
          { input: '128', expected: '64' },
          { input: '256', expected: '128' },
          { input: '192', expected: '96' }
        ],
        solution:`function solve(input){const k=Number(input.trim());return String(Math.floor(k/2));}`
      },
      game:'grover',
      quiz:{q:'Post-quantum recommendation for AES?',opts:['Stop using AES','Use AES-256','AES-128 is fine forever','Switch to RSA'],correct:1,ok:'AES-256 withstands Grover with comfortable margin.',no:'Use AES-256. Grover weakens AES-128 too much for long-term use.'}},
    {id:'t56',title:'Elliptic curve cryptography (ECC)',
      learn:`<b>ECC</b> uses points on elliptic curves instead of big integer factoring. Smaller keys, same security classically (P-256 ≈ RSA-3072). It's everywhere: TLS 1.3, Bitcoin, SSH, code signing. <b>Shor's algorithm</b> solves the elliptic curve discrete logarithm problem — so ECC falls exactly like RSA. P-256, secp256k1, Curve25519 — all need PQC replacement.`,
      deep:`Common curves: <b>NIST P-256</b> (government/TLS), <b>Curve25519/X25519</b> (modern TLS, Signal). ECC key exchange (ECDHE) provides forward secrecy. Post-quantum migration replaces ECDHE with hybrid classical+PQC (e.g. X25519+Kyber) in TLS 1.3 implementations.`,
      keyPoints:['Smaller keys than RSA classically','Shor breaks elliptic curve discrete log','P-256, X25519 widely deployed','Replace with PQC KEMs during migration'],
      analogy:`ECC is a compact high-security lock — elegant and strong today, but Shor is a master key that opens every curve-based lock.`,
      res:[['↗ SafeCurves','https://safecurves.cr.yp.to/'],['↗ Dan Boneh crypto course','https://crypto.stanford.edu/~dabo/courses/OnlineCrypto/']],
      steps:['Find ECC in your stack: browser TLS, SSH, mobile apps.','Understand: ECDHE gives forward secrecy per session.','Note: every ECC deployment needs a PQC migration plan.'],
      game:null,
      quiz:{q:'Why must ECC be replaced post-quantum?',opts:['Keys are too small','Shor breaks the elliptic curve discrete log problem','Grover breaks it','It is deprecated'],correct:1,ok:'Shor solves ECDLP — same fatal class as RSA.',no:'Shor breaks the elliptic curve discrete log — ECC is not quantum-safe.'}},
    {id:'t57',title:'PKI, certificates & TLS',
      learn:`<b>PKI</b> (Public Key Infrastructure) is how the internet trusts public keys. A <b>certificate</b> (X.509) binds a public key to a domain name, signed by a <b>Certificate Authority</b>. Your browser chains trust to root CAs. <b>TLS</b> uses this for HTTPS: certificate proves identity, key exchange establishes session keys, AES encrypts data. Quantum breaks the asymmetric pieces — certificates and key exchange — not the symmetric bulk encryption.`,
      deep:`TLS 1.3 handshake: ClientHello → ServerHello + certificate + key share → shared secret → AES-GCM records. Vulnerable elements: RSA/ECC certificates and ECDHE key exchange. Migration path: hybrid PQC key exchange, PQC-capable certificates, crypto-agile libraries (OpenSSL 3.x + liboqs).`,
      keyPoints:['Certificates bind keys to identities','CA chain = web of trust','TLS = cert + key exchange + symmetric','PQC migration targets asymmetric TLS pieces'],
      analogy:`PKI is the passport system for keys. TLS is the secure tunnel built after checking passports and agreeing on a session cipher.`,
      res:[['↗ Lets Encrypt docs','https://letsencrypt.org/docs/'],['↗ TLS 1.3 handshake','https://www.cloudflare.com/learning/ssl/what-happens-in-a-tls-handshake/']],
      steps:['Visit a site, click the padlock → view certificate chain.','Identify: RSA or ECDSA cert? ECDHE key exchange?','Read a TLS 1.3 handshake diagram.','Try Hybrid TLS Builder game →'],
      game:'hybrid',
      quiz:{q:'In HTTPS, what does a certificate prove?',opts:['The password is correct','The public key belongs to that domain/entity','The data is encrypted with AES','The server is fast'],correct:1,ok:'Certificates bind a public key to an identity via CA signatures.',no:'A certificate proves the public key belongs to the claimed domain/entity.'}},
    {id:'t58',title:'Digital signatures',
      learn:`A <b>digital signature</b> proves who sent data and that it wasn't tampered with. Sign with your <b>private key</b>; anyone verifies with your <b>public key</b>. RSA and ECDSA signatures are broken by Shor. Post-quantum replacements: <b>Dilithium (ML-DSA)</b> for general use, <b>SLH-DSA</b> as a hash-based backup. Code signing, firmware updates, and blockchain all depend on signatures.`,
      deep:`Signature flow: hash message → sign hash with private key → verifier hashes and checks with public key. PQC signatures are larger than ECDSA (kilobytes vs 64 bytes) — impacts TLS, IoT, and embedded systems. Plan for bandwidth and storage in migration.`,
      keyPoints:['Signatures = authenticity + integrity','RSA/ECDSA broken by Shor','Dilithium (FIPS 204) = primary PQC signature','SLH-DSA (FIPS 205) = conservative backup'],
      analogy:`A wax seal on a letter — only you have the seal stamp (private key), anyone can compare to your published seal pattern (public key).`,
      res:[['↗ NIST FIPS 204','https://csrc.nist.gov/pubs/fips/204/final']],
      steps:['Understand: encryption vs signing use keys differently.','List systems using signatures: git commits, app updates, PDFs.','Read NIST FIPS 204 overview for Dilithium.'],
      game:null,
      quiz:{q:'Which NIST standard covers PQC digital signatures (Dilithium)?',opts:['FIPS 203','FIPS 204','FIPS 205','FIPS 140'],correct:1,ok:'FIPS 204 = ML-DSA (Dilithium). FIPS 203 = KEM, 205 = hash-based.',no:'FIPS 204 standardizes ML-DSA (Dilithium) signatures.'}}
  ]},

  L6:{icon:'⚔️',tag:'Level 6',name:'The Quantum Threat',desc:'Cryptanalysis, timelines, resource estimates, side channels',color:'red',topics:[
    {id:'t61',title:'Mapping attacks to targets',
      learn:`The full picture: <b>Shor</b> breaks RSA, ECC, Diffie-Hellman (all asymmetric). <b>Grover</b> halves symmetric strength (AES, hashes). So asymmetric crypto is in mortal danger; symmetric just needs bigger keys. This map tells defenders exactly what to replace first.`,
      analogy:`A doctor's triage: asymmetric crypto is critical (replace now), symmetric is stable (just strengthen). Knowing severity guides the response.`,
      res:[],
      steps:['Memorize: Shor→asymmetric (fatal), Grover→symmetric (manageable).','List what your systems use.','Prioritize asymmetric replacement.'],
      exercise:{
        prompt:`Classify the target. Input: <code>rsa</code>, <code>ecc</code>, <code>dh</code>, <code>aes</code>, or <code>sha</code> (lowercase). Return <code>shor</code> or <code>grover</code>.`,
        formatExample:'Return the word "shor" or "grover" as a string',
        hints:['RSA, ECC, DH → discrete log / factoring → Shor.','AES and SHA search space → Grover.'],
        starter:`function solve(input) {\n  const x = input.trim().toLowerCase();\n  return '';\n}\n`,
        tests:[
          { input: 'rsa', expected: 'shor' },
          { input: 'aes', expected: 'grover' },
          { input: 'ecc', expected: 'shor' },
          { input: 'sha', expected: 'grover' }
        ],
        solution:`function solve(input){const x=input.trim().toLowerCase();if(x==='aes'||x==='sha')return 'grover';return 'shor';}`
      },
      game:null,
      quiz:{q:'Which crypto is in the MOST danger from quantum?',opts:['Symmetric (AES)','Asymmetric (RSA/ECC/DH)','Hashing','All equally safe'],correct:1,ok:'Asymmetric is fatal (Shor). Symmetric just needs bigger keys (Grover).',no:'Asymmetric crypto. Shor destroys it. Symmetric only needs larger keys.'}},
    {id:'t62',title:'When will the threat arrive?',
      learn:`Today's quantum computers are too small and noisy to break RSA — that needs millions of stable qubits; we have hundreds of noisy ones. Estimates range from 10 to 20+ years. But "harvest now, decrypt later" means defenders can't wait for certainty. The migration must happen before the threat lands.`,
      analogy:`You don't wait for the flood to buy insurance. The uncertainty in timing is exactly why early migration is rational.`,
      res:[],
      steps:['Understand: current hardware can\'t break RSA yet.','Cryptographically-relevant quantum computer = years away, uncertain.','Migration must precede the threat (harvest-now risk).'],
      game:null,
      quiz:{q:'Why migrate before quantum computers can break RSA?',opts:['It\'s cheaper now','Harvest-now-decrypt-later + uncertain timing','RSA is already broken','For fun'],correct:1,ok:'Harvested data + uncertain timelines = migrate early or lose long-term secrets.',no:'Because data stolen now gets decrypted later, and the timeline is uncertain.'}},
    {id:'t63',title:'Side-channel & implementation attacks',
      learn:`Even quantum-safe algorithms can leak secrets through <b>side channels</b> — timing, power consumption, electromagnetic emissions during computation. A perfect algorithm with a sloppy implementation is still breakable. This is a huge real-world concern for deploying post-quantum crypto correctly.`,
      analogy:`A perfect safe is useless if you whisper the combination while opening it. The math can be flawless but the implementation leaks.`,
      res:[],
      steps:['Understand: the algorithm AND its code both matter.','Side channels: timing, power, EM emissions.','Constant-time implementations defend against this.'],
      game:null,
      quiz:{q:'What is a side-channel attack?',opts:['Breaking the math directly','Exploiting physical leaks like timing/power','A type of quantum gate','Guessing the key'],correct:1,ok:'It exploits physical leakage (timing, power, EM) — not the math itself.',no:'It exploits implementation leaks: timing, power draw, EM — not the algorithm\'s math.'}},
    {id:'t64',title:'Resource estimation — breaking RSA-2048',
      learn:`How many qubits to break RSA-2048? Estimates vary, but credible analyses suggest <b>millions of physical qubits</b> with error correction — far beyond today's ~100–1000 noisy qubits. Gate counts are in the billions; circuit depth matters. Cryptanalysts publish "resource estimates" so defenders know timelines. This is why the threat is years away — but HNDL means you can't wait to start migrating.`,
      deep:`Rough landscape (2024–2026 estimates): factoring RSA-2048 may need ~20M physical qubits or ~4000 logical qubits depending on assumptions, error rates, and algorithm optimizations. Watch arXiv quant-ph for updated estimates. Your job as a defender: track estimates, don't assume "never" — plan migration on risk, not certainty.`,
      keyPoints:['RSA-2048 needs millions of qubits (estimates)','Error correction multiplies physical qubit count','Timelines uncertain — risk-based migration','Resource estimation = cryptanalysis career skill'],
      analogy:`Breaking RSA today is like reaching Mars — we know the physics works, but we don't have the rocket yet. Estimators track when the rocket might exist.`,
      res:[['↗ Gidney RSA-2048 resource estimate','https://arxiv.org/abs/2505.15917'],['↗ arXiv quant-ph','https://arxiv.org/list/quant-ph/recent']],
      steps:['Read one recent RSA resource estimation paper abstract.','Compare physical vs logical qubit counts.','Connect to QEC topic: why millions of physical qubits are needed.'],
      game:'factor',
      quiz:{q:'Why can\'t today\'s quantum computers break RSA-2048 yet?',opts:['RSA was patched','Not enough stable qubits + error correction overhead','Shor doesn\'t work on large numbers','AES protects RSA'],correct:1,ok:'Scale and error correction — we need far more qubits than exist today.',no:'Today\'s machines lack the millions of error-corrected qubits estimates require.'}},
    {id:'t65',title:'CNSA 2.0 & migration policy',
      learn:`Governments set deadlines. <b>CNSA 2.0</b> (NSA Commercial National Security Algorithm Suite 2.0) directs US national security systems toward PQC. NIST publishes migration timelines. Enterprises use <b>crypto inventories</b> — catalog every algorithm in every system — then prioritize. Replace asymmetric first; upgrade symmetric key sizes; test hybrid deployments.`,
      deep:`Typical migration phases: (1) Discover — inventory all crypto. (2) Prioritize — asymmetric, long-lived data first. (3) Pilot — hybrid TLS in test environments. (4) Deploy — production cutover with rollback plans. (5) Deprecate — remove RSA/ECC where possible.`,
      keyPoints:['CNSA 2.0 = US gov PQC direction','Crypto inventory before migration','Asymmetric replacement is priority #1','Hybrid deployments reduce risk'],
      analogy:`Renovating a skyscraper's wiring: map every circuit first, replace the most dangerous old wiring first, test new circuits before ripping out the old.`,
      res:[['↗ NIST migration project','https://www.nist.gov/cybersecurity/post-quantum-cryptography'],['↗ NSA CNSA 2.0','https://www.nsa.gov/Press-Room/Press-Releases-Statements/Press-Release-View/Article/3588029/']],
      steps:['Draft a crypto inventory template (system, algorithm, data lifetime).','Read NIST migration whitepaper executive summary.','Play Migration Triage game →'],
      game:'triage',
      quiz:{q:'First priority in a PQC migration?',opts:['Upgrade all passwords','Replace vulnerable asymmetric crypto (RSA/ECC/DH)','Deploy QKD everywhere','Stop using TLS'],correct:1,ok:'Asymmetric crypto is fatally threatened by Shor — replace first.',no:'Replace asymmetric crypto first — Shor makes it the critical urgency.'}}
  ]},

  L7:{icon:'🛡️',tag:'Level 7',name:'The Defenses',desc:'NIST PQC, Kyber, Dilithium, hybrid TLS, QKD, QRNG',color:'green',topics:[
    {id:'t71',title:'NIST post-quantum standards',
      learn:`In 2024 NIST finalized the core standards: <b>FIPS 203</b> (ML-KEM / Kyber — key encapsulation), <b>FIPS 204</b> (ML-DSA / Dilithium — signatures), <b>FIPS 205</b> (SLH-DSA / SPHINCS+ — hash-based backup). Additional algorithms (e.g. FN-DSA/Falcon) are also being standardized. All rely on math problems with no known efficient quantum attack. Every RSA/ECC deployment must plan migration to these.`,
      deep:`Algorithm families in NIST process: <b>Lattice</b> (Kyber, Dilithium — primary), <b>Hash-based</b> (SLH-DSA — conservative), <b>Code-based</b> (Classic McEliece — niche), <b>Isogeny</b> (broken SIKE — lesson in validation). Industry focus: Kyber for KEM, Dilithium for signatures.`,
      keyPoints:['FIPS 203 = ML-KEM (Kyber)','FIPS 204 = ML-DSA (Dilithium)','FIPS 205 = SLH-DSA (hash-based)','Migration is global and underway'],
      analogy:`New lock models designed so the coming master key (Shor) can't open them. Now the world swaps its locks.`,
      res:[['↗ NIST PQC','https://www.nist.gov/cybersecurity/post-quantum-cryptography'],['↗ Kyber code','https://github.com/pq-crystals/kyber'],['↗ liboqs','https://github.com/open-quantum-safe/liboqs']],
      extraResources:[['↗ FIPS 203 (ML-KEM)','https://csrc.nist.gov/pubs/fips/203/final'],['↗ FIPS 204 (ML-DSA)','https://csrc.nist.gov/pubs/fips/204/final'],['↗ FIPS 205 (SLH-DSA)','https://csrc.nist.gov/pubs/fips/205/final']],
      steps:['Learn the three standards and their jobs.','Read the NIST overview.','Skim the Kyber GitHub README.','Browse liboqs supported algorithms list.'],
      game:null,
      quiz:{q:'What is FIPS 203 (ML-KEM/Kyber) for?',opts:['Signatures','Key exchange/encapsulation','Hashing','Random numbers'],correct:1,ok:'ML-KEM = key encapsulation (key exchange). 204/205 handle signatures.',no:'FIPS 203 is key encapsulation — quantum-safe key exchange.'}},
    {id:'t72',title:'Quantum Key Distribution (QKD)',
      learn:`<b>QKD</b> uses physics, not math, to share keys. Protocols like <b>BB84</b> send photons; any eavesdropper measuring them disturbs them detectably. The security comes from quantum mechanics itself — not from a hard math problem. Downside: needs special hardware and fiber/line-of-sight.`,
      analogy:`A letter written in disappearing ink that smudges if anyone reads it in transit. You always know if it was intercepted.`,
      res:[['↗ IBM Learning','https://quantum.cloud.ibm.com/learning']],
      steps:['Understand BB84: photons + basis choices.','Eavesdropping disturbs photons → detectable.','Simulate eavesdrop detection in the BB84 game →'],
      game:'bb84',
      quiz:{q:'How does QKD detect eavesdroppers?',opts:['Strong passwords','Measuring photons disturbs them detectably','Faster computers','Bigger keys'],correct:1,ok:'Physics: measurement disturbs the photons, revealing interception.',no:'Any measurement disturbs the quantum states — detectable by the parties.'}},
    {id:'t73',title:'Quantum Random Number Generation',
      learn:`Good crypto needs <b>true randomness</b>. Classical computers fake it (pseudo-random). <b>QRNG</b> uses quantum effects — like which way a photon splits — to produce genuinely unpredictable numbers. This strengthens key generation across all cryptography, quantum or classical.`,
      analogy:`Software randomness is a very complex but ultimately predictable recipe. Quantum randomness is a genuinely unpredictable coin flip baked into physics.`,
      res:[],
      steps:['Understand: classical RNG is deterministic (fakeable).','QRNG uses quantum measurement = true randomness.','This underpins secure key generation everywhere.'],
      game:null,
      quiz:{q:'Why is QRNG valuable for cryptography?',opts:['It\'s faster','It produces true unpredictable randomness','It needs no hardware','It replaces all encryption'],correct:1,ok:'True quantum randomness beats predictable pseudo-random generators for key generation.',no:'It gives genuine, physically-unpredictable randomness — better keys.'}},
    {id:'t74',title:'How Kyber (ML-KEM) works',
      learn:`<b>Kyber</b> is a <b>KEM</b> (Key Encapsulation Mechanism). Alice runs KeyGen → public key pk. Bob calls Encaps(pk) → shared secret ss + ciphertext c. Alice calls Decaps(sk, c) → same ss. Security from <b>Module-LWE</b>: finding secret vectors in noisy lattice equations. Parameter sets: 512, 768, 1024 (security levels 1, 3, 5).`,
      deep:`KEM vs encryption: KEM is designed for key establishment — Bob generates ss and encrypts it in c; only Alice recovers ss. TLS 1.3 hybrid combines X25519 output with Kyber ss via KDF. Implementation pitfalls: side channels in polynomial multiplication, constant-time decapsulation.`,
      keyPoints:['KEM = encapsulate shared secret','Module-LWE hardness','ML-KEM-768 is common default','Used in hybrid TLS migrations'],
      analogy:`Kyber is a locked box only Alice can open — Bob puts a random secret inside, sends the box, Alice opens it. They never send the secret in the clear.`,
      res:[['↗ Kyber spec (pq-crystals)','https://pq-crystals.org/kyber/'],['↗ NIST FIPS 203','https://csrc.nist.gov/pubs/fips/203/final']],
      steps:['Read Kyber "How it works" page.','Trace: KeyGen → Encaps → Decaps flow.','Clone pq-crystals/kyber and build the C reference.','Play Lattice Puzzle →'],
      exercise:{
        prompt:`Map NIST PQC standards to names. Input: <code>kem</code>, <code>sig</code>, or <code>hashsig</code> → output FIPS number.`,
        starter:`function solve(input) {\n  const x = input.trim().toLowerCase();\n  // Map kem / sig / hashsig to FIPS numbers\n  return '';\n}\n`,
        tests:[
          { input: 'kem', expected: '203' },
          { input: 'sig', expected: '204' },
          { input: 'hashsig', expected: '205' }
        ],
        solution:`function solve(input){const x=input.trim().toLowerCase();if(x==='kem')return '203';if(x==='sig')return '204';if(x==='hashsig')return '205';return '';}`
      },
      flashcards:[{q:'ML-KEM is which FIPS?',a:'FIPS 203.'},{q:'What does a KEM output?',a:'Shared secret + ciphertext.'}],
      game:'lattice',
      quiz:{q:'What does a KEM produce?',opts:['Only a public key','A shared secret + ciphertext','A digital signature','A hash'],correct:1,ok:'Encaps outputs (ss, c); Decaps recovers ss — designed for key exchange.',no:'A KEM outputs a shared secret and ciphertext for key establishment.'}},
    {id:'t75',title:'Dilithium & SLH-DSA signatures',
      learn:`<b>Dilithium (ML-DSA)</b> signs messages using lattice problems (Module-LWE / Module-SIS). Fast, primary NIST signature standard. <b>SLH-DSA (SPHINCS+)</b> is hash-based — slower, larger signatures, but conservative (minimal new assumptions). Use Dilithium for most apps; SLH-DSA when you want hash-only trust.`,
      deep:`Signature sizes matter: ECDSA P-256 ≈ 64 bytes; Dilithium2 ≈ 2.4 KB; SLH-DSA can be tens of KB. Embedded systems and bandwidth-limited protocols need careful choice. FN-DSA (Falcon) offers smaller signatures but trickier implementation.`,
      keyPoints:['Dilithium = primary PQC signature','SLH-DSA = hash-based backup','Larger signatures than ECDSA','Plan bandwidth in TLS and firmware'],
      analogy:`Dilithium is your new wax seal — bigger stamp, quantum-proof. SLH-DSA is a seal carved only from trusted wood (hash functions).`,
      res:[['↗ Dilithium','https://pq-crystals.org/dilithium/'],['↗ FIPS 204','https://csrc.nist.gov/pubs/fips/204/final']],
      steps:['Compare ECDSA vs Dilithium signature sizes.','Read FIPS 204 introduction.','Sign a test message with liboqs Dilithium demo.'],
      game:null,
      quiz:{q:'When might you choose SLH-DSA over Dilithium?',opts:['When you need smallest signatures','When you want hash-only security assumptions','When encrypting bulk data','For key exchange'],correct:1,ok:'SLH-DSA relies only on hash functions — conservative choice.',no:'SLH-DSA uses hash functions only — chosen when you want minimal new assumptions.'}},
    {id:'t76',title:'Hybrid TLS migration',
      learn:`<b>Hybrid</b> deployments run classical + PQC algorithms together during migration. Example: <b>X25519 + ML-KEM-768</b> in TLS 1.3 — attacker must break BOTH to compromise the session. Browsers and servers are enabling PQC hybrids in 2024–2026. This is the practical path enterprises use today.`,
      deep:`OpenSSL 3.x + oqs-provider or BoringSSL experiments support hybrid groups. Test in staging: latency, handshake size, middlebox compatibility. Rollback plan if legacy proxies break. Monitor IETF CFRG and TLS working group for standard hybrid code points.`,
      keyPoints:['Hybrid = classical + PQC','X25519+Kyber is common pattern','Defense in depth during transition','Test before production cutover'],
      analogy:`Two locks on one door — a thief needs to pick both. During renovation, you keep the old lock until the new one is proven.`,
      res:[['↗ Cloudflare PQC TLS','https://blog.cloudflare.com/post-quantum-cryptography/'],['↗ Open Quantum Safe','https://openquantumsafe.org/']],
      steps:['Enable PQC in a test browser (Chrome flags / Cloudflare test).','Read one hybrid TLS deployment blog post.','Play Hybrid TLS Builder game →'],
      game:'hybrid',
      quiz:{q:'Why use hybrid classical+PQC key exchange?',opts:['It is faster than either alone','Attacker must break both; safer during migration','PQC is not ready','It removes certificates'],correct:1,ok:'Hybrid = defense in depth while PQC matures in production.',no:'Hybrid requires breaking both algorithms — safer during the transition period.'}},
    {id:'t77',title:'QKD limitations & real-world security',
      learn:`QKD is powerful but not magic. <b>Authentication problem</b>: initial key establishment needs classical auth — MITM possible without it. <b>Distance limits</b> (~100–200 km fiber). <b>Trusted nodes</b> in networks. <b>Implementation attacks</b>: detector blinding, Trojan-horse. QKD complements PQC; it doesn't replace software crypto for the open internet.`,
      deep:`When QKD makes sense: government backbone links, data centers, financial hubs with dedicated fiber. When PQC makes sense: internet-scale TLS, cloud, mobile. CV-QKD and device-independent QKD are research frontiers. Always combine QKD keys with proper authentication (pre-shared keys or classical signatures).`,
      keyPoints:['QKD needs authenticated channel setup','Distance and rate limits','Not a drop-in for public HTTPS','Complements PQC for niche links'],
      analogy:`QKD is a tamper-evident armored courier between two buildings — great for that route, but you still need passports (authentication) and a global postal system (PQC/TLS) for everyone else.`,
      res:[['↗ ETSI QKD standards','https://www.etsi.org/technologies/quantum-key-distribution']],
      steps:['List QKD advantages vs limitations.','Read about detector blinding attacks (survey paper).','Compare: when would your org use QKD vs PQC?'],
      game:'bb84',
      quiz:{q:'Why can\'t QKD alone secure the public internet?',opts:['Photons are too slow','Distance limits, authentication needs, and infrastructure cost','It is broken by Shor','It does not use math'],correct:1,ok:'Infrastructure, distance, and authentication limit QKD to specialized links.',no:'Distance, authentication requirements, and cost limit QKD to specialized deployments.'}},
    {id:'t78',title:'Code-based crypto & algorithm diversity',
      learn:`NIST selected multiple families for resilience. <b>Classic McEliece</b> (code-based) has huge public keys but decades of study. <b>Lattice</b> (Kyber/Dilithium) leads deployments. <b>Hash-based</b> (SLH-DSA) is conservative. Diversity protects against breakthrough attacks on any one family. Crypto-agility lets you swap algorithms if one weakens.`,
      deep:`McEliece public keys can be hundreds of KB — fine for stored keys, awkward for ephemeral TLS. Stay aware of NIST status and academic attacks (e.g. SIKE isogeny break 2022). Your migration architecture should support multiple PQC algorithms via configuration, not hardcoding.`,
      keyPoints:['Multiple families reduce systemic risk','McEliece = large keys, long track record','Crypto-agility = swap algorithms via config','Monitor research for breaks'],
      analogy:`Don't bet the farm on one crop — plant several. If blight hits wheat, you still have corn.`,
      res:[['↗ Classic McEliece','https://classic.mceliece.org/']],
      steps:['Skim Classic McEliece parameter size table.','Understand why NIST kept multiple families.','Design a config-driven crypto policy template.'],
      game:null,
      quiz:{q:'Why does NIST standardize multiple PQC algorithm families?',opts:['To confuse attackers','Diversity — a break in one family doesn\'t break everything','McEliece is fastest','Only for patents'],correct:1,ok:'Algorithm diversity limits damage if one family is broken.',no:'Multiple families ensure a single breakthrough doesn\'t compromise all PQC.'}}
    ,{id:'t79',title:'Exercise: toy LWE key exchange (in code)',
      learn:`In practice, Kyber is built on structured lattices (Module-LWE). Here we’ll do a <b>toy LWE-style</b> step to build intuition: compute a noisy value <code>b = a·s + e (mod q)</code>. The noise <code>e</code> hides the secret <code>s</code> from an attacker who sees only <code>a</code> and <code>b</code>.`,
      deep:`Real LWE works in high dimensions and uses carefully-chosen distributions. This toy exercise is not secure, but it teaches the shape of the hardness assumption: recovering secrets from noisy modular equations.\n\nKyber uses polynomials and module structure for efficiency; the “noise” is a small polynomial. The security story is still: <b>noise makes inversion hard</b> while legitimate parties can still agree on a shared secret via encapsulation/decapsulation.\n\nAs a defender or implementer, you don’t roll your own LWE. You learn the intuition so you can reason about parameters, side channels, and migration choices.\n\nIn the exercise, you’ll implement modular arithmetic correctly — a skill you need for understanding any lattice-based scheme.`,
      keyPoints:['Toy formula: b = a·s + e (mod q)','Noise e hides s from simple inversion','Real schemes use high-dimensional structured lattices','Correct modular arithmetic (including negatives) matters','This is intuition-building, not real security'],
      analogy:`It’s like shouting a message with a bit of random static added. Friends who know the protocol still understand; eavesdroppers can’t cleanly reverse it.`,
      res:[['↗ LWE overview (NIST PQC)','https://www.nist.gov/cybersecurity/post-quantum-cryptography'],['↗ Kyber spec','https://pq-crystals.org/kyber/']],
      steps:['Understand the toy equation b = a·s + e (mod q).','Practice mod with negatives (ensure result is 0..q-1).','Implement the exercise and run tests.'],
      exercise:{
        prompt:`Implement <b>solve(input)</b>.\n<br/><br/>Input: <code>a s e q</code> (integers).\nCompute <code>b = (a*s + e) mod q</code> and return <code>b</code>.\n<br/><br/>Important: the result must be in <code>0..q-1</code> even if intermediate values are negative.`,
        starter:`function solve(input) {\n  const [a,s,e,q] = input.trim().split(/\\s+/).map(Number);\n  // TODO: compute (a*s + e) mod q in range 0..q-1\n  return '';\n}\n`,
        tests:[
          { input: '3 4 1 7', expected: '6' },
          { input: '5 6 0 7', expected: '2' },
          { input: '2 3 -1 7', expected: '5' },
          { input: '-2 3 0 7', expected: '1' }
        ],
        solution:`function solve(input){const [a,s,e,q]=input.trim().split(/\\s+/).map(Number);let b=a*s+e;b=((b%q)+q)%q;return String(b);}`
      },
      game:'lattice',
      quiz:{q:'What does the noise term e do in LWE-style equations?',opts:['Makes math faster','Hides the secret so inversion is hard','Removes modular arithmetic','Makes b equal to s'],correct:1,ok:'Noise hides the secret, making recovery hard even though forward computation is easy.',no:'Noise hides the secret — it’s what makes inversion hard.'}}
  ]},

  L8:{icon:'🎓',tag:'Level 8',name:'Specialization Branches',desc:'PQC & cryptanalysis tracks + labs + career branches',color:'gold',topics:[
    {id:'t81',track:'pqc',trackLabel:'🔐 Post-Quantum Cryptography Track',title:'PQC track — overview',
      learn:`The largest industry path: <b>lattice-based PQC</b> (ML-KEM/Kyber, ML-DSA/Dilithium), secure implementation, and enterprise <b>migration</b> into TLS and PKI. Work through the 7 topics below in order.`,
      deep:`This track mirrors how teams actually deploy quantum-safe crypto: understand LWE → understand Kyber/Dilithium → integrate via audited libraries → harden against side channels → migrate with hybrids and crypto-agility.\n\nNIST standards: <b>FIPS 203</b> (ML-KEM), <b>FIPS 204</b> (ML-DSA), <b>FIPS 205</b> (SLH-DSA backup).`,
      keyPoints:['FIPS 203/204/205 are the core standards','Start with LWE intuition','Use liboqs for hands-on integration','Plan hybrid TLS migrations'],
      analogy:`The global lock replacement project — every TLS handshake and certificate eventually touched.`,
      res:[['↗ NIST PQC','https://www.nist.gov/cybersecurity/post-quantum-cryptography']],
      steps:['Skim the seven PQC track topics below.','Complete t79 LWE exercise in Level 7 first if you skipped it.','Pick one liboqs command to run this week.'],
      flashcards:[{q:'Which FIPS standard is Kyber (ML-KEM)?',a:'FIPS 203.'},{q:'Which FIPS standard is Dilithium (ML-DSA)?',a:'FIPS 204.'}],
      game:null,
      quiz:{q:'What math problem underpins Kyber/ML-KEM?',opts:['Factoring','Discrete log','Module-LWE (structured lattices)','Sorting'],correct:2,ok:'Module-LWE — no known efficient quantum attack (unlike factoring/discrete log).',no:'Kyber/ML-KEM security is based on Module-LWE hardness, not factoring or discrete log.'}},
    ...PQC_TRACK,
    {id:'t82',title:'Branch 2 — Quantum Key Distribution',
      learn:`The physics-and-hardware path. You'd study photon optics, protocols (BB84, E91), security proofs, and real quantum networks. Tied to academia, national labs, and telecom. Smaller field, more research-oriented, genuinely cutting-edge.`,
      analogy:`Building the unbreakable physical phone line, photon by photon. Deep, specialized, research-flavored.`,
      res:[['↗ MIT OCW QIS','https://ocw.mit.edu/courses/8-370x-quantum-information-science-i-spring-2018/']],
      steps:['Study BB84 and E91 protocols deeply.','Learn photon polarization basics.','Read about real quantum network testbeds.','Run the BB84 game →'],
      game:'bb84',
      quiz:{q:'QKD\'s security comes from?',opts:['Hard math problems','The laws of quantum physics','Big key sizes','Fast computers'],correct:1,ok:'Physics itself — measurement disturbs quantum states. Not math-based.',no:'Quantum physics: you can\'t measure without disturbing. Not a math assumption.'}},
    {id:'t83',track:'cryptanalysis',trackLabel:'⚔️ Quantum Cryptanalysis Track',title:'Cryptanalysis track — overview',
      learn:`The offensive lens: understand <b>Shor</b>, <b>Grover</b>, resource estimates, and how to read attack papers — so you know what is actually breakable and when migration is urgent.`,
      deep:`Cryptanalysis here is not “illegal hacking” — it is rigorous analysis of attack costs. Defenders use the same math to set timelines and priorities.\n\nWork through the six topics below: classical baselines → Shor/QFT intuition → RSA-2048 estimates → Grover tuning → symmetric impacts → paper reading.`,
      keyPoints:['Shor breaks RSA/ECC/DH assumptions','Grover weakens symmetric key sizes','Resource estimates drive migration planning','Read papers for assumptions + QEC overhead'],
      analogy:`Red-team for physics — you stress-test the locks so everyone knows which to replace first.`,
      res:[['↗ IBM: Shor & Grover','https://quantum.cloud.ibm.com/learning']],
      steps:['Skim the six cryptanalysis topics below.','Play Attack RSA and Grover Search games.','Read one quant-ph abstract (t8c6).'],
      flashcards:[{q:'What does Shor break?',a:'RSA, DH, ECC — problems based on factoring or discrete log.'},{q:'Grover effect on AES-128?',a:'Effective security drops to ~64 bits — use AES-256.'}],
      game:'rsa',
      quiz:{q:'What does quantum cryptanalysis focus on?',opts:['Defending systems','Building & analyzing attacks to find weaknesses','Writing policy','Making random numbers'],correct:1,ok:'Offensive analysis informs defense and migration.',no:'Building/analyzing attacks to reveal what is vulnerable.'}},
    ...CRYPT_TRACK,
    {id:'t84',title:'Branch 4 — Quantum RNG',
      learn:`A focused hardware-and-theory niche: designing and certifying <b>quantum random number generators</b>. You'd work on entropy sources, randomness extraction, and certification standards. Foundational because every key starts with randomness. Found in hardware security companies and standards bodies.`,
      analogy:`Crafting the perfect dice that physics guarantees can never be loaded. Niche but foundational.`,
      res:[],
      steps:['Study entropy sources (photon splitting, vacuum noise).','Learn randomness extraction & testing.','Read randomness certification standards.'],
      game:null,
      quiz:{q:'Why is QRNG foundational to all crypto?',opts:['It encrypts data','Every key needs true randomness to start','It replaces RSA','It\'s the fastest method'],correct:1,ok:'All keys begin with randomness — QRNG makes that genuinely unpredictable.',no:'Every cryptographic key needs strong randomness; QRNG provides true randomness.'}},
    {id:'t85',title:'Branch 5 — Quantum-Safe Governance',
      learn:`The least math-heavy, high-demand path: <b>crypto-agility</b>, key management, risk assessment, compliance, and migration strategy at the organizational level. You'd help companies inventory their crypto, prioritize, and transition. Great for those who like security + strategy over deep math.`,
      analogy:`The project manager of the great crypto migration — making sure the whole organization swaps its locks in the right order, on time.`,
      res:[['↗ NIST migration guidance','https://www.nist.gov/cybersecurity/post-quantum-cryptography']],
      steps:['Learn "crypto-agility" (easy algorithm swapping).','Study how to inventory an org\'s cryptography.','Read NIST migration playbooks.'],
      game:null,
      quiz:{q:'What is "crypto-agility"?',opts:['Fast encryption','Ability to swap crypto algorithms easily','A quantum gate','A key size'],correct:1,ok:'Designing systems so algorithms can be replaced easily — key for migration.',no:'Crypto-agility = building systems that can swap algorithms easily.'}},
    {id:'t86',title:'Branch 6 — Quantum Network Security',
      learn:`The frontier: securing actual <b>quantum networks</b> — entanglement distribution, quantum repeaters, and the future "quantum internet." Combines QKD, networking, and physics. Very research-heavy and emerging, mostly in labs and advanced telecom R&D.`,
      analogy:`Building the secure internet of the quantum age — laying entanglement "cables" between cities. Pioneering and largely unbuilt.`,
      res:[],
      steps:['Understand entanglement distribution over distance.','Learn what quantum repeaters do.','Read about quantum internet roadmaps.'],
      game:null,
      quiz:{q:'What problem do quantum repeaters solve?',opts:['Slow encryption','Extending entanglement over long distances','Generating keys','Storing data'],correct:1,ok:'They extend fragile entanglement across distance — key to a quantum internet.',no:'Quantum repeaters extend entanglement over long distances.'}},
    {id:'t87',title:'Hands-on: liboqs & OpenSSL PQC',
      learn:`<b>liboqs</b> (Open Quantum Safe) implements NIST PQC algorithms in C for testing and integration. Pair with <b>OpenSSL 3.x</b> and the oqs-provider to run Kyber/Dilithium in TLS. This is how engineers actually touch PQC before production — build, benchmark, break in a lab.`,
      deep:`Workflow: clone liboqs → build → run test_kem/test_sig → install oqs-provider → openssl s_client with hybrid groups. Compare handshake sizes and latency vs classical-only. Document results for your migration business case.`,
      keyPoints:['liboqs = reference PQC implementations','oqs-provider adds PQC to OpenSSL','Test hybrids in staging first','Benchmark before production'],
      analogy:`Test-driving new brakes on a closed track before highway driving — liboqs is the test track for PQC.`,
      res:[['↗ liboqs GitHub','https://github.com/open-quantum-safe/liboqs'],['↗ oqs-provider','https://github.com/open-quantum-safe/oqs-provider']],
      steps:['Clone liboqs, follow BUILD.md (Linux/WSL recommended).','Run test_kem for Kyber768.','Install oqs-provider, run openssl list -kem-algorithms.','Capture one hybrid TLS handshake with Wireshark.'],
      code:`<span class="cc"># After building liboqs:</span>
./build/tests/test_kem kyber768
<span class="cc"># OpenSSL with oqs-provider:</span>
openssl s_client -connect pq.cloudflareresearch.com:443 -groups X25519MLKEM768`,
      game:'hybrid',
      quiz:{q:'What is liboqs primarily for?',opts:['Breaking RSA','Testing and integrating PQC algorithms','Running Shor on hardware','Replacing TLS'],correct:1,ok:'liboqs provides implementations for experimentation and integration.',no:'liboqs implements PQC algorithms for testing and integration into systems like OpenSSL.'}},
    {id:'t88',title:'Lab: crypto inventory & migration plan',
      learn:`Real migration starts with a <b>crypto inventory</b>: every system, protocol, algorithm, key size, and data sensitivity. Score risk: asymmetric + long-lived data = critical. Output a phased plan with owners and dates. This is the #1 deliverable for governance and security architects.`,
      deep:`Inventory columns: Asset | Protocol | Algorithm | Key size | Data lifetime | Owner | PQC status | Target date. Example row: Customer DB TLS | TLS 1.3 | ECDHE P-256 + AES-128-GCM | 128-bit sym | 15 years | Platform team | Not started | Q3 hybrid pilot.`,
      keyPoints:['Inventory before replacement','Score by algorithm + data lifetime','Assign owners and dates','Pilot hybrids before cutover'],
      analogy:`Renovation spreadsheet for every lock in a building — you can't replace what you haven't catalogued.`,
      res:[['↗ NIST migration whitepaper','https://www.nist.gov/cybersecurity/post-quantum-cryptography']],
      steps:['Create a spreadsheet with the inventory columns above.','Fill 10 real or hypothetical rows.','Mark 3 as critical (asymmetric + long-lived).','Play Migration Triage to validate priorities →'],
      game:'triage',
      quiz:{q:'What is the first step in enterprise PQC migration?',opts:['Deploy Kyber everywhere tomorrow','Crypto inventory of all systems','Buy a quantum computer','Disable RSA'],correct:1,ok:'You must know what crypto you have before you can replace it.',no:'Start with a crypto inventory — catalog every algorithm in use.'}},
    {id:'t89',title:'Choose your specialization path',
      learn:`Six branches: <b>PQC engineering</b> (most jobs — Kyber, TLS, libraries), <b>QKD/quantum networks</b> (physics, telecom), <b>cryptanalysis</b> (offensive, resource estimates), <b>QRNG</b> (hardware entropy), <b>governance</b> (policy, inventory, compliance), <b>quantum networking</b> (research frontier). Pick based on skills: math+code → PQC; physics → QKD; strategy → governance.`,
      deep:`PQC engineers need: C/Rust, TLS, number theory basics, NIST specs. QKD researchers need: quantum optics, information theory. Governance leads need: risk frameworks, NIST/CNSA timelines, stakeholder management. Most learners aiming for industry should prioritize PQC + migration skills.`,
      keyPoints:['PQC = largest job market','Match branch to your strengths','Build one portfolio project per branch interest','Depth beats breadth for hiring'],
      analogy:`Medical specialties after med school — same foundation, different clinics. Your L0–L7 foundation is done; now pick the clinic.`,
      res:[['↗ PQShield careers blog','https://pqshield.com/'],['↗ IACR jobs','https://www.iacr.org/jobs/']],
      steps:['Score each branch 1–5 on interest and skill fit.','Pick top branch.','Define one 4-week project (e.g. hybrid TLS demo).','Start this week — not "someday."'],
      game:null,
      quiz:{q:'Which branch has the broadest industry job market today?',opts:['Quantum internet only','Post-quantum cryptography engineering','QRNG only','Pure theory'],correct:1,ok:'PQC engineering and migration dominate industry demand.',no:'Post-quantum cryptography engineering has the largest industry job market today.'}}
  ]},

  L9:{icon:'🚀',tag:'Capstone',name:'Where To Go Next',desc:'Hero projects, certifications, career launch',color:'sky',topics:[
    {id:'t91',title:'Build a portfolio',
      learn:`Knowledge gets you started; <b>projects</b> get you hired. Build and publish: your quantum simulator, a BB84 implementation, a Kyber demo, write-ups of attacks you ran. A public GitHub of real quantum-security projects beats any certificate.`,
      analogy:`A chef is hired for dishes they\'ve cooked, not recipes they\'ve read. Build the dishes.`,
      res:[['↗ GitHub','https://github.com/']],
      steps:['Put your simulator on GitHub with a clear README.','Add a BB84 or Kyber demo.','Write a short blog post explaining one attack.'],
      game:null,
      quiz:{q:'What matters most for getting hired?',opts:['Certificates only','Published real projects','Watching videos','Memorizing terms'],correct:1,ok:'Real, published projects demonstrate ability better than anything.',no:'Built and published projects — they prove you can actually do it.'}},
    {id:'t92',title:'Practice, compete, connect',
      learn:`Sharpen skills with <b>CTFs</b> (Capture The Flag crypto challenges), read <b>arXiv</b> quant-ph papers, join communities (Qiskit Slack, crypto forums), and consider certifications as a supplement. Pick a branch, go deep, and keep building. You now have the full map — the rest is doing.`,
      analogy:`You\'ve learned the language; now go live in the country. Immersion through practice and community is how mastery happens.`,
      res:[['↗ arXiv quant-ph','https://arxiv.org/list/quant-ph/recent'],['↗ IBM Learning','https://quantum.cloud.ibm.com/learning']],
      steps:['Try a beginner crypto CTF.','Read one arXiv quant-ph abstract per week.','Join a quantum/crypto community.','Pick your branch and go deep.'],
      game:null,
      quiz:{q:'You\'ve finished the map. What\'s the final step?',opts:['Stop learning','Pick a branch, build, and stay engaged','Re-read Level 0','Wait for quantum computers'],correct:1,ok:'Pick a branch, build real things, stay in the community. You\'re ready. 🚀',no:'Choose a specialization, keep building projects, and engage with the community.'}},
    {id:'t93',title:'Hero capstone projects',
      learn:`Ship these to go from learner to practitioner: (1) <b>Quantum simulator</b> in Python/NumPy. (2) <b>BB84 simulator</b> with eavesdropper detection. (3) <b>Kyber KEM demo</b> using liboqs. (4) <b>Hybrid TLS capture</b> + write-up. (5) <b>Crypto inventory</b> for a fictional enterprise. (6) <b>Migration whitepaper</b> (5 pages). Any two prove serious intent; all six make a standout portfolio.`,
      deep:`Each project README should explain: threat model, what you built, how to reproduce, what you learned. Blog posts (Medium/Dev.to) double hiring visibility. Present at a local security meetup or university seminar.`,
      keyPoints:['Projects > certificates alone','Reproducible READMEs','Write-ups show communication skills','Two projects minimum, six = exceptional'],
      analogy:`A pilot's logbook — hours flown matter more than textbooks read.`,
      res:[['↗ GitHub Pages','https://pages.github.com/']],
      steps:['Pick project #1 and #3 from the list.','Create public GitHub repos with READMEs.','Write a 500-word blog post on one finding.','Link all projects in your resume/LinkedIn.'],
      game:null,
      quiz:{q:'What impresses employers most in quantum security?',opts:['Only online courses','Published, reproducible projects with clear write-ups','Memorizing NIST document numbers','Having a quantum computer'],correct:1,ok:'Real repos + clear communication beat passive learning.',no:'Published projects with reproducible code and write-ups impress employers most.'}},
    {id:'t94',title:'Certifications, CTFs & continuous learning',
      learn:`Supplements (not replacements): <b>crypto CTFs</b> (CryptoHack, picoCTF), <b>CISSP/CCSP</b> for governance roles, vendor PQC workshops, <b>IACR</b> conferences. Read <b>arXiv quant-ph</b> weekly. Follow NIST PQC mailing list. Quantum security evolves fast — schedule 5 hours/week maintenance learning forever.`,
      deep:`Learning loop: Monday — one paper abstract. Wednesday — 1 CTF challenge. Friday — code 30 min on portfolio. Monthly — attend one webinar. Yearly — one conference (PQCrypto, QCrypt, Real World Crypto).`,
      keyPoints:['CTFs sharpen practical crypto','Conferences for networking','NIST mailing list for standards updates','Learning never stops in this field'],
      analogy:`Doctors do continuing education — quantum security moves faster than most medicine.`,
      res:[['↗ CryptoHack','https://cryptohack.org/'],['↗ PQCrypto conference','https://pqcrypto.org/']],
      steps:['Create a CryptoHack account, finish one challenge.','Subscribe to NIST PQC updates.','Block 5 hrs/week on your calendar for maintenance learning.','Play Entropy Meter game as a final check →'],
      game:'entropy',
      quiz:{q:'Best long-term habit for a quantum security career?',opts:['Stop learning after this app','Continuous projects + papers + community','Only read news headlines','Avoid coding'],correct:1,ok:'Continuous building and learning — the field never stands still.',no:'Continuous projects, reading, and community engagement — the field evolves constantly.'}}
  ]}
};
